export default Layout;

import React from 'react';
import { Product, Sale } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ICONS } from '../constants';

interface DashboardProps {
  products: Product[];
  sales: Sale[];
}

const Dashboard: React.FC<DashboardProps> = ({ products, sales }) => {
  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();

  const monthlySales = sales.filter(s => {
    const d = new Date(s.date);
    return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
  });

  const totalSold = monthlySales.reduce((acc, s) => acc + s.finalPrice, 0);
  const totalProfit = monthlySales.reduce((acc, s) => acc + s.profit, 0);
  const totalPurchase = monthlySales.reduce((acc, s) => acc + s.purchasePrice, 0);

  const profitPercentage = totalPurchase > 0 ? (totalProfit / totalPurchase) * 100 : 0;
  const itemsSold = monthlySales.length;

  const data = monthlySales.slice(0, 7).reverse().map((s, i) => ({
    name: `Venda ${i + 1}`,
    valor: s.finalPrice,
    lucro: s.profit
  }));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold">Dashboard</h2>
          <p className="text-slate-400">Resumo de desempenho para este mês.</p>
        </div>
        <div className="flex items-center gap-2 bg-slate-800/50 px-4 py-2 rounded-full text-sm border border-slate-700">
          <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
          Sistema Online
        </div>
      </header>

      {/* Metric Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="flex justify-between items-start mb-4">
            <div className="bg-blue-500/10 p-3 rounded-2xl text-blue-500">
              {ICONS.Money}
            </div>
            <span className="text-xs font-bold text-green-500 bg-green-500/10 px-2 py-1 rounded-full">+12%</span>
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Total Vendido</p>
          <h3 className="text-2xl font-bold">R$ {totalSold.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="flex justify-between items-start mb-4">
            <div className="bg-green-500/10 p-3 rounded-2xl text-green-500">
              {ICONS.Profit}
            </div>
            <span className="text-xs font-bold text-green-500 bg-green-500/10 px-2 py-1 rounded-full">+R$ 250</span>
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Lucro Acumulado</p>
          <h3 className="text-2xl font-bold">R$ {totalProfit.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="flex justify-between items-start mb-4">
            <div className="bg-purple-500/10 p-3 rounded-2xl text-purple-500">
              {ICONS.Produtos}
            </div>
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Itens Vendidos</p>
          <h3 className="text-2xl font-bold">{itemsSold} <span className="text-slate-500 text-base font-normal">unidades</span></h3>
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="flex justify-between items-start mb-4">
            <div className="bg-orange-500/10 p-3 rounded-2xl text-orange-500">
              {ICONS.BarChart3}
            </div>
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Média Lucro</p>
          <h3 className="text-2xl font-bold">{profitPercentage.toFixed(1)}%</h3>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Chart */}
        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl h-[400px]">
          <h4 className="text-lg font-bold mb-6">Últimas Vendas (Valores)</h4>
          <ResponsiveContainer width="100%" height="80%">
            <BarChart data={data}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
              <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `R$${val}`} />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', borderRadius: '12px' }}
                itemStyle={{ color: '#f8fafc' }}
              />
              <Bar dataKey="valor" radius={[4, 4, 0, 0]}>
                {data.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#3b82f6' : '#22c55e'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Available Products Highlights */}
        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl overflow-hidden">
          <div className="flex justify-between items-center mb-6">
            <h4 className="text-lg font-bold">Disponíveis em Estoque</h4>
            <button className="text-blue-500 text-sm font-semibold">Ver todos</button>
          </div>
          <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
            {products.filter(p => p.status === 'Disponível').map(p => (
              <div key={p.id} className="flex items-center justify-between p-4 bg-slate-800/30 rounded-2xl border border-slate-700/50">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-slate-700 rounded-xl flex items-center justify-center font-bold text-slate-400">
                    {p.name.charAt(0)}
                  </div>
                  <div>
                    <p className="font-semibold">{p.name}</p>
                    <p className="text-xs text-slate-500">{p.category}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-blue-400">R$ {p.suggestedPrice.toFixed(2)}</p>
                  <p className="text-[10px] text-green-500">+{(((p.suggestedPrice - p.purchasePrice) / p.purchasePrice) * 100).toFixed(0)}% lucro</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Product, ProductStatus } from '../types';
import { ICONS, CATEGORIES } from '../constants';

interface ProductListProps {
  products: Product[];
  onAdd: (p: any) => void;
  onDelete: (id: string) => void;
  onSell: (id: string) => void;
}

const ProductList: React.FC<ProductListProps> = ({ products, onAdd, onDelete, onSell }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [filter, setFilter] = useState<string>('');
  const [categoryFilter, setCategoryFilter] = useState<string>('Todas');

  const filteredProducts = products.filter(p => {
    const matchesName = p.name.toLowerCase().includes(filter.toLowerCase());
    const matchesCat = categoryFilter === 'Todas' || p.category === categoryFilter;
    return matchesName && matchesCat;
  });

  const [newProduct, setNewProduct] = useState({
    name: '',
    category: CATEGORIES[0],
    purchasePrice: 0,
    suggestedPrice: 0
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newProduct.name && newProduct.purchasePrice > 0) {
      onAdd(newProduct);
      setNewProduct({ name: '', category: CATEGORIES[0], purchasePrice: 0, suggestedPrice: 0 });
      setShowAddModal(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold">Produtos</h2>
          <p className="text-slate-400">Gerencie seu estoque e margens.</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-900/20 transition-all active:scale-95"
        >
          {ICONS.Plus} Novo Produto
        </button>
      </header>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="flex-1 relative">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">{ICONS.Filter}</span>
          <input 
            type="text" 
            placeholder="Buscar por nome..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all"
          />
        </div>
        <select 
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
          className="bg-slate-800 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-blue-500 appearance-none"
        >
          <option>Todas</option>
          {CATEGORIES.map(c => <option key={c}>{c}</option>)}
        </select>
      </div>

      {/* Grid of Product Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredProducts.map(p => {
          const profitPerc = ((p.suggestedPrice - p.purchasePrice) / p.purchasePrice) * 100;
          const isSold = p.status === 'Vendido';

          return (
            <div key={p.id} className={`bg-card rounded-3xl border ${isSold ? 'border-slate-800 opacity-75' : 'border-slate-800'} overflow-hidden shadow-xl transition-all hover:border-slate-700`}>
              <div className="p-6">
                <div className="flex justify-between items-start mb-4">
                  <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-1 rounded-full ${isSold ? 'bg-red-500/10 text-red-500' : 'bg-green-500/10 text-green-500'}`}>
                    {p.status}
                  </span>
                  <p className="text-xs text-slate-500">{p.category}</p>
                </div>
                <h3 className="text-xl font-bold mb-1 truncate">{p.name}</h3>

                <div className="mt-6 space-y-3">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Preço Compra:</span>
                    <span className="font-bold">R$ {p.purchasePrice.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Venda Sugerida:</span>
                    <span className="font-bold text-blue-400">R$ {p.suggestedPrice.toFixed(2)}</span>
                  </div>
                  <div className="pt-3 border-t border-slate-800 flex justify-between items-center">
                    <span className="text-xs text-slate-500 font-semibold uppercase">Margem Lucro</span>
                    <span className="text-lg font-black text-green-500">{profitPerc.toFixed(0)}%</span>
                  </div>
                </div>
              </div>

              {!isSold && (
                <div className="p-3 bg-slate-800/50 flex gap-2">
                  <button 
                    onClick={() => onSell(p.id)}
                    className="flex-1 bg-green-600 hover:bg-green-700 py-3 rounded-xl text-sm font-bold transition-all active:scale-95"
                  >
                    Vender
                  </button>
                  <button 
                    onClick={() => onDelete(p.id)}
                    className="p-3 bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white rounded-xl transition-all"
                  >
                    {ICONS.Trash}
                  </button>
                </div>
              )}
              {isSold && (
                <div className="p-4 bg-slate-900 text-center text-xs text-slate-500 italic">
                  Item vendido em {new Date(p.createdAt).toLocaleDateString()}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Add Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-8">
              <h3 className="text-2xl font-bold mb-6">Novo Produto</h3>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input 
                    required
                    type="text" 
                    value={newProduct.name}
                    onChange={e => setNewProduct({...newProduct, name: e.target.value})}
                    placeholder="Ex: Tênis Air Max"
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                  <select 
                    value={newProduct.category}
                    onChange={e => setNewProduct({...newProduct, category: e.target.value})}
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 appearance-none"
                  >
                    {CATEGORIES.map(c => <option key={c}>{c}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      value={newProduct.purchasePrice || ''}
                      onChange={e => setNewProduct({...newProduct, purchasePrice: parseFloat(e.target.value)})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      value={newProduct.suggestedPrice || ''}
                      onChange={e => setNewProduct({...newProduct, suggestedPrice: parseFloat(e.target.value)})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button 
                    type="button"
                    onClick={() => setShowAddModal(false)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    className="flex-1 bg-blue-600 hover:bg-blue-700 py-4 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20"
                  >
                    Salvar
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductList;

import React, { useState, useEffect } from 'react';
import { Product } from '../types';

interface SellProductModalProps {
  product: Product;
  onClose: () => void;
  onConfirm: (finalPrice: number, cash: number, tradeVal: number, tradeName?: string) => void;
}

const SellProductModal: React.FC<SellProductModalProps> = ({ product, onClose, onConfirm }) => {
  const [cashAmount, setCashAmount] = useState<number>(product.suggestedPrice);
  const [tradeItemValue, setTradeItemValue] = useState<number>(0);
  const [tradeItemName, setTradeItemName] = useState<string>('');

  const finalPrice = cashAmount + tradeItemValue;
  const realProfit = finalPrice - product.purchasePrice;

  return (
