import React, { useState } from 'react';
import { Sale, Product } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface ReportsProps {
  sales: Sale[];
  products: Product[];
}

const Reports: React.FC<ReportsProps> = ({ sales, products }) => {
  const [period, setPeriod] = useState('Geral');

  const totalSold = sales.reduce((acc, s) => acc + s.finalPrice, 0);
  const totalProfit = sales.reduce((acc, s) => acc + s.profit, 0);

  // Group by category
  const categoryDataMap: Record<string, number> = {};
  sales.forEach(s => {
    // Find category from products (or snapshot it in real app)
    const category = products.find(p => p.id === s.productId)?.category || 'Outros';
    categoryDataMap[category] = (categoryDataMap[category] || 0) + s.finalPrice;
  });

  const categoryData = Object.entries(categoryDataMap).map(([name, value]) => ({ name, value }));
  const COLORS = ['#3b82f6', '#22c55e', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899'];

  return (
    <div className="space-y-8 animate-in zoom-in-95 duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold">Relatórios</h2>
          <p className="text-slate-400">Visão analítica do seu negócio.</p>
        </div>
        <select 
          value={period}
          onChange={(e) => setPeriod(e.target.value)}
          className="bg-slate-800 border-none rounded-2xl px-4 py-2 text-sm"
        >
          <option>Geral</option>
          <option>Hoje</option>
          <option>Últimos 7 dias</option>
          <option>Mês Atual</option>
        </select>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-card p-6 rounded-3xl border border-slate-800">
            <h4 className="text-slate-400 text-sm font-bold uppercase mb-4">Métricas Consolidadas</h4>
            <div className="space-y-6">
              <div>
                <p className="text-2xl font-bold">R$ {totalSold.toLocaleString('pt-BR')}</p>
                <p className="text-xs text-slate-500">Volume Total de Vendas</p>
              </div>
              <div>
                <p className="text-2xl font-bold text-green-500">R$ {totalProfit.toLocaleString('pt-BR')}</p>
                <p className="text-xs text-slate-500">Lucro Real Líquido</p>
              </div>
              <div>
                <p className="text-2xl font-bold text-blue-500">{sales.length}</p>
                <p className="text-xs text-slate-500">Vendas Registradas</p>
              </div>
            </div>
          </div>

          <div className="bg-blue-600 p-6 rounded-3xl text-white shadow-xl shadow-blue-900/20">
            <h4 className="font-bold mb-2">Dica de Performance</h4>
            <p className="text-sm text-blue-100 opacity-90 leading-relaxed">
              Suas trocas representam {(sales.filter(s => s.tradeItemValue > 0).length / sales.length * 100 || 0).toFixed(0)}% das negociações. Considere aumentar a margem nesses produtos para maior rentabilidade.
            </p>
          </div>
        </div>

        <div className="lg:col-span-2 bg-card p-6 rounded-3xl border border-slate-800 h-[450px]">
          <h4 className="text-lg font-bold mb-6">Vendas por Categoria</h4>
          <ResponsiveContainer width="100%" height="80%">
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip 
