import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProductList from './components/ProductList';
import SalesList from './components/SalesList';
import Reports from './components/Reports';
import SellProductModal from './components/SellProductModal';
import { useAppState } from './hooks/useAppState';
import { Product } from './types';

const App: React.FC = () => {
  const { 
    products, 
    sales, 
    currentView, 
    setCurrentView, 
    addProduct, 
    deleteProduct, 
    sellProduct 
  } = useAppState();

  const [productToSell, setProductToSell] = useState<Product | null>(null);

  const handleSellConfirmation = (finalPrice: number, cash: number, tradeVal: number, tradeName?: string) => {
    if (productToSell) {
      sellProduct(productToSell.id, finalPrice, cash, tradeVal, tradeName);
      setProductToSell(null);
      setCurrentView('Vendas');
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'Dashboard':
        return <Dashboard products={products} sales={sales} />;
      case 'Produtos':
        return (
          <ProductList 
            products={products} 
            onAdd={addProduct} 
            onDelete={deleteProduct} 
            onSell={(id) => setProductToSell(products.find(p => p.id === id) || null)} 
          />
        );
      case 'Vendas':
        return <SalesList sales={sales} />;
      case 'Relatórios':
        return <Reports sales={sales} products={products} />;
      case 'Configurações':
        return (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center animate-in fade-in">
             <div className="bg-slate-800 p-8 rounded-[3rem] border border-slate-700 max-w-md">
               <h2 className="text-2xl font-bold mb-4">Administração</h2>
               <p className="text-slate-400 mb-6">Versão 1.0.0 Pro - Geyser Edition</p>
               <button 
                onClick={() => {
                  if(confirm("Deseja realmente limpar todos os dados?")) {
                    localStorage.clear();
                    window.location.reload();
                  }
                }}
                className="w-full py-4 bg-red-500/10 text-red-500 rounded-2xl font-bold hover:bg-red-500 hover:text-white transition-all"
               >
                 Limpar Base de Dados
               </button>
             </div>
          </div>
        );
      default:
        return <Dashboard products={products} sales={sales} />;
    }
  };

  return (
    <Layout currentView={currentView} setCurrentView={setCurrentView}>
      {renderView()}

      {productToSell && (
        <SellProductModal 
          product={productToSell} 
          onClose={() => setProductToSell(null)}
          onConfirm={handleSellConfirmation}
        />
      )}
    </Layout>
  );
};

export default App;

