                <div className="text-right">
                  <p className="text-[10px] text-slate-500 uppercase font-bold">Venda</p>
                  <p className="font-bold text-blue-400">R$ {s.finalPrice.toFixed(2)}</p>
                </div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-500 uppercase font-bold">Lucro</p>
                  <p className="font-bold text-green-500">R$ {s.profit.toFixed(2)}</p>
                </div>
                {s.tradeItemValue > 0 && (
                  <div className="bg-blue-500/10 px-3 py-1 rounded-full border border-blue-500/20 flex items-center gap-2">
                    <span className="text-blue-400">{ICONS.Trade}</span>
                    <span className="text-[10px] font-bold text-blue-400 uppercase">Troca</span>
                  </div>
                )}
                <button 
                  onClick={() => handleDeleteClick(s.id, s.productName)}
                  className="p-3 text-slate-500 hover:text-red-500 transition-colors"
                  title="Excluir Venda"
                >
                  {ICONS.Trash}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

