import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProductList from './components/ProductList';
import SalesList from './components/SalesList';
import Reports from './components/Reports';
import SellProductModal from './components/SellProductModal';
import ConfirmModal from './components/ConfirmModal';
import { useAppState } from './hooks/useAppState';
import { Product } from './types';

const App: React.FC = () => {
  const { 
    products, 
    sales, 
    currentView, 
    setCurrentView, 
    addProduct,
    updateProduct,
    deleteProduct, 
    deleteSale,
    sellProduct 
  } = useAppState();

  const [productToSell, setProductToSell] = useState<Product | null>(null);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  const handleSellConfirmation = (finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string) => {
    if (productToSell) {
      sellProduct(productToSell.id, finalPrice, cash, tradeVal, date, tradeName);
      setProductToSell(null);
      setCurrentView('Vendas');
    }
  };

  const handleResetDatabase = () => {
    localStorage.clear();
    window.location.reload();
  };

  const renderView = () => {
    switch (currentView) {
      case 'Dashboard':
        return <Dashboard products={products} sales={sales} />;
      case 'Produtos':
        return (
          <ProductList 
            products={products} 
            onAdd={addProduct} 
            onUpdate={updateProduct}
            onDelete={deleteProduct} 
            onSell={(id) => setProductToSell(products.find(p => p.id === id) || null)} 
          />
        );
      case 'Vendas':
        return <SalesList sales={sales} onDeleteSale={deleteSale} />;
      case 'Relatórios':
        return <Reports sales={sales} products={products} />;
      case 'Configurações':
        return (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center animate-in fade-in">
             <div className="bg-slate-800 p-8 rounded-[3rem] border border-slate-700 max-w-md w-full">
               <h2 className="text-2xl font-bold mb-4 text-white">Administração</h2>
               <p className="text-slate-400 mb-8">Versão 1.2.0 Pro - Geyser Edition</p>
               <button 
                onClick={() => setShowResetConfirm(true)}
                className="w-full py-4 bg-red-500/10 text-red-500 rounded-2xl font-bold hover:bg-red-500 hover:text-white transition-all shadow-lg active:scale-95"
               >
                 Limpar Base de Dados
               </button>

               <div className="mt-8 pt-8 border-t border-slate-700">
                  <p className="text-xs text-slate-500 uppercase tracking-widest font-bold mb-4 text-left px-2">Exportar Dados</p>
                  <button className="w-full py-4 bg-slate-700/50 text-slate-300 rounded-2xl font-bold hover:bg-slate-700 transition-all text-sm mb-3 opacity-50 cursor-not-allowed">
                    Backup para Nuvem (Breve)
                  </button>
               </div>
             </div>

             <ConfirmModal 
                isOpen={showResetConfirm}
                title="Limpar Sistema?"
                message="Deseja realmente limpar todos os dados do sistema? Esta ação removerá permanentemente todos os produtos, vendas e configurações. Não poderá ser desfeita."
                confirmText="Limpar Tudo"
                onConfirm={handleResetDatabase}
                onCancel={() => setShowResetConfirm(false)}
             />
          </div>
        );
      default:
        return <Dashboard products={products} sales={sales} />;
    }
  };

  return (
    <Layout currentView={currentView} setCurrentView={setCurrentView}>
      {renderView()}

      {productToSell && (
        <SellProductModal 
          product={productToSell} 
          onClose={() => setProductToSell(null)}
          onConfirm={handleSellConfirmation}
        />
      )}
    </Layout>
  );
};

export default App;

import { useState, useEffect, useCallback } from 'react';
import { Product, Sale, View } from '../types';

const STORAGE_KEY_PRODUCTS = 'brixlucro_products';
const STORAGE_KEY_SALES = 'brixlucro_sales';

const INITIAL_PRODUCTS: Product[] = [
  { id: '1', name: 'iPhone 13 128GB', category: 'Eletrônicos', purchasePrice: 3500, suggestedPrice: 4800, status: 'Disponível', createdAt: new Date().toISOString() },
  { id: '2', name: 'Camiseta Premium XL', category: 'Vestuário', purchasePrice: 45, suggestedPrice: 120, status: 'Disponível', createdAt: new Date().toISOString() },
  { id: '3', name: 'Fone Bluetooth Pro', category: 'Acessórios', purchasePrice: 180, suggestedPrice: 350, status: 'Vendido', createdAt: new Date().toISOString() },
];

const INITIAL_SALES: Sale[] = [
  { 
    id: 's1', 
    productId: '3', 
    productName: 'Fone Bluetooth Pro', 
    date: new Date().toISOString(), 
    finalPrice: 330, 
    cashAmount: 330, 
    tradeItemValue: 0, 
    purchasePrice: 180, 
    profit: 150 
  }
];

export const useAppState = () => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PRODUCTS);
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SALES);
    return saved ? JSON.parse(saved) : INITIAL_SALES;
  });

  const [currentView, setCurrentView] = useState<View>('Dashboard');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PRODUCTS, JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SALES, JSON.stringify(sales));
  }, [sales]);

  const addProduct = (p: Omit<Product, 'id' | 'createdAt' | 'status'>) => {
    const newProduct: Product = {
      ...p,
      id: crypto.randomUUID(),
      status: 'Disponível',
      createdAt: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSale = (id: string) => {
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const sellProduct = (
    productId: string, 
    finalPrice: number, 
    cashAmount: number, 
    tradeItemValue: number, 
    date: string,
    tradeItemName?: string,
    tradeItemCategory?: string
  ) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    // 1. Create Sale Record
    const newSale: Sale = {
      id: crypto.randomUUID(),
      productId: product.id,
      productName: product.name,
      date: date,
      finalPrice: finalPrice,
      cashAmount: cashAmount,
      tradeItemValue: tradeItemValue,
      tradeItemName: tradeItemName,
      purchasePrice: product.purchasePrice,
      profit: finalPrice - product.purchasePrice
    };

    // 2. Update Product Status
    setProducts(prev => prev.map(p => p.id === productId ? { ...p, status: 'Vendido' } : p));

    // 3. Add to sales history
    setSales(prev => [newSale, ...prev]);

    // 4. Handle Trade-in logic: Add new product if trade happened
    if (tradeItemValue > 0 && tradeItemName) {
      const tradedProduct: Product = {
        id: crypto.randomUUID(),
        name: tradeItemName,
        category: tradeItemCategory || 'Troca',
        purchasePrice: tradeItemValue,
        suggestedPrice: tradeItemValue * 1.5, // 50% markup for trade items as default
        status: 'Disponível',
        createdAt: new Date().toISOString()
      };
      setProducts(prev => [tradedProduct, ...prev]);
    }
  };

  return {
    products,
    sales,
    currentView,
    setCurrentView,
    addProduct,
    updateProduct,
    deleteProduct,
    deleteSale,
    sellProduct
  };
};

