                <div className="space-y-3">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Preço Compra:</span>
                    <span className="font-bold text-white">R$ {p.purchasePrice.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Venda Sugerida:</span>
                    <span className="font-bold text-blue-400">R$ {p.suggestedPrice.toFixed(2)}</span>
                  </div>
                  <div className="pt-3 border-t border-slate-800 flex justify-between items-center">
                    <span className="text-xs text-slate-500 font-semibold uppercase">Margem Lucro</span>
                    <span className="text-lg font-black text-green-500">{profitPerc.toFixed(0)}%</span>
                  </div>
                </div>
              </div>

              <div className="p-3 bg-slate-800/30 flex gap-2">
                {!isSold ? (
                  <button 
                    onClick={() => onSell(p.id)}
                    className="flex-1 bg-green-600 hover:bg-green-700 py-3 rounded-xl text-sm font-bold transition-all active:scale-95 text-white"
                  >
                    Vender
                  </button>
                ) : (
                  <div className="flex-1 py-3 text-center text-xs text-slate-500 italic rounded-xl bg-slate-800/50">
                    Vendido em {new Date(p.createdAt).toLocaleDateString()}
                  </div>
                )}
                <button 
                  onClick={() => setConfirmDelete({ id: p.id, name: p.name })}
                  className="p-3 bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white rounded-xl transition-all"
                >
                  {ICONS.Trash}
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Empty State */}
      {filteredProducts.length === 0 && (
        <div className="p-20 text-center bg-slate-800/30 rounded-[3rem] border border-dashed border-slate-700">
          <p className="text-slate-500 font-medium">Nenhum produto encontrado nesta categoria.</p>
        </div>
      )}

      {/* Add Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-8">
              <h3 className="text-2xl font-bold mb-6 text-white">Novo Produto</h3>
              <form onSubmit={handleSubmit} className="space-y-5">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden"
                >
                  {newProduct.imageUrl ? (
                    <img src={newProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors mb-2" size={32} />
                      <span className="text-xs font-bold text-slate-500 uppercase">Subir Foto</span>
