                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={editingProduct.purchasePrice || ''}
                      onChange={e => setEditingProduct({...editingProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${editingProduct.purchasePrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {editingProduct.purchasePrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={editingProduct.suggestedPrice || ''}
                      onChange={e => setEditingProduct({...editingProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${editingProduct.suggestedPrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {editingProduct.suggestedPrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button 
                    type="button"
                    onClick={() => setEditingProduct(null)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    disabled={!isEditingProductValid}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed py-4 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20 text-white"
                  >
                    Salvar Alterações
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Confirmation Modal */}
      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir o produto "${confirmDelete?.name}"? Esta ação removerá o item permanentemente do seu estoque.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default ProductList;

import { useState, useEffect, useCallback } from 'react';
import { Product, Sale, View } from '../types';

const STORAGE_KEY_PRODUCTS = 'brixlucro_products';
const STORAGE_KEY_SALES = 'brixlucro_sales';
const STORAGE_KEY_SETTINGS = 'brixlucro_settings';

const INITIAL_PRODUCTS: Product[] = [
  { id: '1', name: 'iPhone 13 128GB', category: 'Celular', purchasePrice: 3500, suggestedPrice: 4800, status: 'Disponível', createdAt: new Date().toISOString() },
  { id: '2', name: 'Camiseta Premium XL', category: 'Vestuário', purchasePrice: 45, suggestedPrice: 120, status: 'Disponível', createdAt: new Date().toISOString() },
  { id: '3', name: 'Fone Bluetooth Pro', category: 'Acessórios', purchasePrice: 180, suggestedPrice: 350, status: 'Vendido', createdAt: new Date().toISOString() },
];

const INITIAL_SALES: Sale[] = [
  { 
    id: 's1', 
    productId: '3', 
    productName: 'Fone Bluetooth Pro', 
    date: new Date().toISOString(), 
    finalPrice: 330, 
    cashAmount: 330, 
    tradeItemValue: 0, 
    purchasePrice: 180, 
    profit: 150 
  }
];

export const useAppState = () => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PRODUCTS);
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SALES);
    return saved ? JSON.parse(saved) : INITIAL_SALES;
  });

  const [settings, setSettings] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SETTINGS);
    return saved ? JSON.parse(saved) : { businessName: 'Meu Negócio' };
  });

  const [currentView, setCurrentView] = useState<View>('Dashboard');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PRODUCTS, JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SALES, JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(settings));
  }, [settings]);

  const addProduct = (p: Omit<Product, 'id' | 'createdAt' | 'status'>) => {
    const newProduct: Product = {
      ...p,
      id: crypto.randomUUID(),
      status: 'Disponível',
      createdAt: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSale = (id: string) => {
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const updateSettings = (newSettings: any) => {
    setSettings(prev => ({ ...prev, ...newSettings }));
  };

  const sellProduct = (
    productId: string, 
    finalPrice: number, 
    cashAmount: number, 
    tradeItemValue: number, 
    date: string,
    tradeName?: string,
    tradeCategory?: string
  ) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    const newSale: Sale = {
      id: crypto.randomUUID(),
      productId: product.id,
      productName: product.name,
      date: date,
      finalPrice: finalPrice,
      cashAmount: cashAmount,
      tradeItemValue: tradeItemValue,
      tradeItemName: tradeName,
      purchasePrice: product.purchasePrice,
      profit: finalPrice - product.purchasePrice
    };

    setProducts(prev => prev.map(p => p.id === productId ? { ...p, status: 'Vendido' } : p));
    setSales(prev => [newSale, ...prev]);

    if (tradeItemValue > 0 && tradeName) {
      const tradedProduct: Product = {
        id: crypto.randomUUID(),
        name: tradeName,
        category: tradeCategory || 'Troca',
        purchasePrice: tradeItemValue,
        suggestedPrice: tradeItemValue * 1.5,
        status: 'Disponível',
        createdAt: new Date().toISOString()
      };
      setProducts(prev => [tradedProduct, ...prev]);
    }
  };

  return {
    products,
    sales,
    settings,
    currentView,
    setCurrentView,
    addProduct,
    updateProduct,
    deleteProduct,
    deleteSale,
    sellProduct,
    updateSettings
  };
};

