    if (confirmDelete) {
      onDeleteSale(confirmDelete.id);
      setConfirmDelete(null);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
      <header>
        <h2 className="text-3xl font-bold text-white">Histórico de Vendas</h2>
        <p className="text-slate-400">Registro detalhado de cada transação realizada.</p>
      </header>

      {sales.length === 0 ? (
        <div className="bg-card p-12 rounded-[2.5rem] text-center border border-slate-800">
          <div className="bg-slate-800 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-500">
            {ICONS.Vendas}
          </div>
          <p className="text-slate-500 font-medium">Nenhuma venda registrada ainda.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {sales.map(s => {
            const hasTrade = s.tradeItemValue > 0;

            return (
              <div key={s.id} className="bg-card p-6 rounded-[2rem] border border-slate-800 shadow-lg transition-all hover:bg-slate-800/40 group">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                  {/* Left: Product Info */}
                  <div className="flex items-center gap-4">
                    <div className="bg-green-500/10 p-4 rounded-2xl text-green-500 group-hover:bg-green-500/20 transition-colors">
                      <Banknote size={24} />
                    </div>
                    <div>
                      <h4 className="font-bold text-xl text-white group-hover:text-blue-400 transition-colors">{s.productName}</h4>
                      <p className="text-xs text-slate-500 flex items-center gap-1.5 mt-1 font-medium">
                        <Calendar size={12} className="text-slate-600" />
                        {new Date(s.date).toLocaleDateString('pt-BR')}
                      </p>
                    </div>
                  </div>

                  {/* Right: Price Summaries & Actions */}
                  <div className="flex flex-wrap items-center gap-6 sm:gap-10">
                    <div className="flex flex-col items-end">
                      <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-1">Total Venda</p>
                      <p className="font-black text-2xl text-blue-400">R$ {s.finalPrice.toFixed(2)}</p>
                    </div>
                    <div className="flex flex-col items-end">
                      <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-1">Lucro Real</p>
                      <div className="bg-green-500/10 px-3 py-1 rounded-lg">
                        <p className="font-black text-lg text-green-500">R$ {s.profit.toFixed(2)}</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => setConfirmDelete({ id: s.id, name: s.productName })}
                      className="p-3 text-slate-600 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"
                      title="Excluir Venda"
                    >
                      {ICONS.Trash}
                    </button>
                  </div>
                </div>

                {/* Details Section for Mixed Sales (Cash + Trade) */}
                {hasTrade && (
                  <div className="mt-6 pt-6 border-t border-slate-800/60 grid grid-cols-1 sm:grid-cols-2 gap-4 animate-in slide-in-from-top-2 duration-300">
                    {/* Cash Part */}
                    <div className="bg-slate-900/40 p-4 rounded-2xl border border-slate-800/50 flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <div className="text-slate-500">{ICONS.Money}</div>
                        <span className="text-sm font-bold text-slate-300">Recebido em Dinheiro</span>
                      </div>
                      <span className="font-bold text-white">R$ {s.cashAmount.toFixed(2)}</span>
                    </div>

                    {/* Trade Part */}
                    <div className="bg-blue-600/5 p-4 rounded-2xl border border-blue-500/20 flex items-center justify-between">
                      <div className="flex items-center gap-3 overflow-hidden">
                        <ArrowRightLeft size={16} className="text-blue-500 shrink-0" />
                        <div className="overflow-hidden">
                          <span className="text-sm font-bold text-blue-300 block leading-tight">Troca: {s.tradeItemName}</span>
                          <span className="text-[10px] text-blue-500/80 font-bold uppercase tracking-wider">Item Recebido</span>
                        </div>
                      </div>
                      <span className="font-bold text-blue-400 ml-4 shrink-0">R$ {s.tradeItemValue.toFixed(2)}</span>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Confirmation Modal */}
      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Registro de Venda"
        message={`Deseja realmente excluir a venda de "${confirmDelete?.name}"? Esta ação removerá o lucro e o valor da venda dos seus relatórios.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default SalesList;

import React, { useState, useRef } from 'react';
import { Product, ProductStatus } from '../types';
import { ICONS, CATEGORIES } from '../constants';
import ConfirmModal from './ConfirmModal';
import { Camera, AlertCircle } from 'lucide-react';

interface ProductListProps {
  products: Product[];
  onAdd: (p: any) => void;
  onUpdate: (p: Product) => void;
  onDelete: (id: string) => void;
}

const ProductList: React.FC<ProductListProps> = ({ products, onAdd, onUpdate, onDelete }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, name: string } | null>(null);
  const [filter, setFilter] = useState<string>('');
  const [categoryFilter, setCategoryFilter] = useState<string>('Todas');
  const [activeTab, setActiveTab] = useState<ProductStatus>('Disponível');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  const [newProduct, setNewProduct] = useState({
    name: '',
    category: CATEGORIES[0],
    purchasePrice: 0,
    suggestedPrice: 0,
    imageUrl: ''
  });

  const isNewProductValid = newProduct.name.trim() !== '' && 
                            newProduct.purchasePrice > 0 && 
                            newProduct.suggestedPrice > 0;

  const isEditingProductValid = editingProduct && 
                                editingProduct.name.trim() !== '' && 
                                editingProduct.purchasePrice > 0 && 
                                editingProduct.suggestedPrice > 0;

  const filteredProducts = products.filter(p => {
    const matchesName = p.name.toLowerCase().includes(filter.toLowerCase());
    const matchesCat = categoryFilter === 'Todas' || p.category === categoryFilter;
    const matchesStatus = p.status === activeTab;
    return matchesName && matchesCat && matchesStatus;
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (isEdit && editingProduct) {
          setEditingProduct({ ...editingProduct, imageUrl: reader.result as string });
        } else {
          setNewProduct({ ...newProduct, imageUrl: reader.result as string });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isNewProductValid) {
      onAdd(newProduct);
      setNewProduct({ name: '', category: CATEGORIES[0], purchasePrice: 0, suggestedPrice: 0, imageUrl: '' });
      setShowAddModal(false);
    }
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isEditingProductValid) {
      onUpdate(editingProduct!);
      setEditingProduct(null);
    }
  };

  const handleConfirmDelete = () => {
    if (confirmDelete) {
      onDelete(confirmDelete.id);
      setConfirmDelete(null);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-white">Produtos</h2>
          <p className="text-slate-400">Gerencie seu estoque e margens.</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-900/20 transition-all active:scale-95"
        >
          {ICONS.Plus} Novo Produto
        </button>
      </header>

      {/* Tabs */}
      <div className="flex bg-slate-800/50 p-1.5 rounded-2xl border border-slate-700 max-w-fit">
        <button
          onClick={() => setActiveTab('Disponível')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'Disponível' 
            ? 'bg-blue-600 text-white shadow-lg' 
            : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          Disponíveis ({products.filter(p => p.status === 'Disponível').length})
        </button>
        <button
          onClick={() => setActiveTab('Vendido')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'Vendido' 
            ? 'bg-red-600 text-white shadow-lg' 
            : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          Vendidos ({products.filter(p => p.status === 'Vendido').length})
        </button>
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="flex-1 relative">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">{ICONS.Filter}</span>
          <input 
            type="text" 
            placeholder="Buscar por nome..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all text-white"
          />
        </div>
        <select 
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
          className="bg-slate-800 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-blue-500 appearance-none text-white min-w-[150px]"
        >
          <option>Todas</option>
          {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      {/* Grid of Product Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredProducts.map(p => {
          const profitPerc = ((p.suggestedPrice - p.purchasePrice) / p.purchasePrice) * 100;
          const isSold = p.status === 'Vendido';

          return (
            <div key={p.id} className={`bg-card rounded-3xl border ${isSold ? 'border-slate-800 opacity-75' : 'border-slate-800'} overflow-hidden shadow-xl transition-all hover:border-slate-700 flex flex-col`}>
              <div className="relative h-48 bg-slate-800 flex items-center justify-center overflow-hidden">
                {p.imageUrl ? (
                  <img src={p.imageUrl} alt={p.name} className="w-full h-full object-cover" />
                ) : (
                  <div className="text-slate-600 flex flex-col items-center gap-2">
                    {ICONS.Produtos}
                    <span className="text-[10px] uppercase font-bold tracking-widest">Sem Foto</span>
                  </div>
                )}
                <div className="absolute top-4 left-4">
                  <span className={`text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-full border ${
                    isSold 
                    ? 'bg-red-500/20 text-red-400 border-red-500/30' 
                    : 'bg-green-500/20 text-green-400 border-green-500/30'
                  } backdrop-blur-md`}>
                    {p.status}
                  </span>
                </div>

                <div className="absolute top-4 right-4 flex gap-2">
                  <button 
                    onClick={() => setEditingProduct(p)}
                    className="p-2 bg-slate-900/60 text-white rounded-xl hover:bg-slate-900 transition-all backdrop-blur-md"
                  >
                    {ICONS.Edit}
                  </button>
                  <button 
                    onClick={() => setConfirmDelete({ id: p.id, name: p.name })}
                    className="p-2 bg-red-500/10 text-red-500 hover:bg-red-500 transition-all rounded-xl backdrop-blur-md"
                  >
                    {ICONS.Trash}
                  </button>
                </div>
              </div>

              <div className="p-6 flex-1">
                <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mb-1">{p.category}</p>
                <h3 className="text-xl font-bold mb-4 truncate text-white">{p.name}</h3>

                <div className="space-y-3">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Preço Compra:</span>
                    <span className="font-bold text-white">R$ {p.purchasePrice.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Venda Sugerida:</span>
                    <span className="font-bold text-blue-400">R$ {p.suggestedPrice.toFixed(2)}</span>
                  </div>
                  <div className="pt-3 border-t border-slate-800 flex justify-between items-center">
                    <span className="text-xs text-slate-500 font-semibold uppercase">Margem Lucro</span>
                    <span className="text-lg font-black text-green-500">{profitPerc.toFixed(0)}%</span>
                  </div>
                </div>
              </div>

              {isSold && (
                <div className="p-4 bg-slate-800/30 text-center">
                  <div className="py-2 text-xs text-slate-500 italic rounded-xl bg-slate-800/50">
                    Vendido em {new Date(p.createdAt).toLocaleDateString()}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Empty State */}
      {filteredProducts.length === 0 && (
        <div className="p-20 text-center bg-slate-800/30 rounded-[3rem] border border-dashed border-slate-700">
          <p className="text-slate-500 font-medium">Nenhum produto encontrado nesta categoria.</p>
        </div>
      )}

      {/* Add Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-8">
              <h3 className="text-2xl font-bold mb-6 text-white">Novo Produto</h3>
              <form onSubmit={handleSubmit} className="space-y-5">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden"
                >
                  {newProduct.imageUrl ? (
                    <img src={newProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors mb-2" size={32} />
                      <span className="text-xs font-bold text-slate-500 uppercase">Subir Foto</span>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={(e) => handleImageUpload(e, false)} 
                    className="hidden" 
                    accept="image/*" 
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input 
                    required
                    type="text" 
                    value={newProduct.name}
                    onChange={e => setNewProduct({...newProduct, name: e.target.value})}
                    placeholder="Ex: Tênis Air Max"
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                  <select 
                    value={newProduct.category}
                    onChange={e => setNewProduct({...newProduct, category: e.target.value})}
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 appearance-none text-white"
                  >
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={newProduct.purchasePrice || ''}
                      onChange={e => setNewProduct({...newProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${newProduct.purchasePrice <= 0 && newProduct.purchasePrice !== 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {newProduct.purchasePrice <= 0 && newProduct.purchasePrice !== 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={newProduct.suggestedPrice || ''}
                      onChange={e => setNewProduct({...newProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${newProduct.suggestedPrice <= 0 && newProduct.suggestedPrice !== 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {newProduct.suggestedPrice <= 0 && newProduct.suggestedPrice !== 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button 
                    type="button"
                    onClick={() => setShowAddModal(false)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    disabled={!isNewProductValid}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed py-4 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20 text-white"
                  >
                    Salvar
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Edit Modal */}
      {editingProduct && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-8">
              <h3 className="text-2xl font-bold mb-6 text-white">Editar Produto</h3>
              <form onSubmit={handleEditSubmit} className="space-y-5">
                <div 
                  onClick={() => editFileInputRef.current?.click()}
                  className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden"
                >
                  {editingProduct.imageUrl ? (
                    <img src={editingProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors mb-2" size={32} />
                      <span className="text-xs font-bold text-slate-500 uppercase">Alterar Foto</span>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={editFileInputRef} 
                    onChange={(e) => handleImageUpload(e, true)} 
                    className="hidden" 
                    accept="image/*" 
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input 
                    required
                    type="text" 
                    value={editingProduct.name}
                    onChange={e => setEditingProduct({...editingProduct, name: e.target.value})}
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                  <select 
                    value={editingProduct.category}
                    onChange={e => setEditingProduct({...editingProduct, category: e.target.value})}
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 appearance-none text-white"
                  >
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={editingProduct.purchasePrice || ''}
                      onChange={e => setEditingProduct({...editingProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${editingProduct.purchasePrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {editingProduct.purchasePrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={editingProduct.suggestedPrice || ''}
                      onChange={e => setEditingProduct({...editingProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${editingProduct.suggestedPrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {editingProduct.suggestedPrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button 
                    type="button"
                    onClick={() => setEditingProduct(null)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    disabled={!isEditingProductValid}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed py-4 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20 text-white"
                  >
                    Salvar Alterações
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Confirmation Modal */}
      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir o produto "${confirmDelete?.name}"? Esta ação removerá o item permanentemente do seu estoque.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default ProductList;

import React, { useState } from 'react';
import { Sale } from '../types';
import { ICONS } from '../constants';
import ConfirmModal from './ConfirmModal';
import { ArrowRightLeft, Banknote, Calendar, Plus } from 'lucide-react';

interface SalesListProps {
  sales: Sale[];
  onDeleteSale: (id: string) => void;
  onNewSale: () => void;
}

