import React, { useState } from 'react';
import { Product } from '../types';
import { CATEGORIES, ICONS } from '../constants';
import { Search, ChevronRight, PackageOpen } from 'lucide-react';

interface SellProductModalProps {
  availableProducts: Product[];
  onClose: () => void;
  onConfirm: (finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string) => void;
}

const SellProductModal: React.FC<SellProductModalProps> = ({ availableProducts, onClose, onConfirm }) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchFilter, setSearchFilter] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const [cashAmount, setCashAmount] = useState<number>(0);
  const [tradeItemValue, setTradeItemValue] = useState<number>(0);
  const [tradeItemName, setTradeItemName] = useState<string>('');
  const [tradeItemCategory, setTradeItemCategory] = useState<string>(CATEGORIES[0]);
  const [saleDate, setSaleDate] = useState<string>(today);

  const filteredItems = availableProducts.filter(p => 
    p.name.toLowerCase().includes(searchFilter.toLowerCase()) || 
    p.category.toLowerCase().includes(searchFilter.toLowerCase())
  );

  const handleSelectProduct = (p: Product) => {
    setSelectedProduct(p);
    setCashAmount(p.suggestedPrice);
  };

  const finalPrice = (cashAmount || 0) + (tradeItemValue || 0);
  const realProfit = selectedProduct ? finalPrice - selectedProduct.purchasePrice : 0;
  const isTradeActive = tradeItemName.length > 0 || tradeItemValue > 0;

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-slate-900 w-full max-w-lg rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">

        {/* Step 1: Selection */}
        {!selectedProduct ? (
          <div className="p-8 flex flex-col h-full overflow-hidden">
            <header className="mb-6">
              <h3 className="text-2xl font-bold text-white">Nova Venda</h3>
              <p className="text-slate-400">Selecione o item que deseja vender.</p>
            </header>

            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                placeholder="Buscar item disponível..."
                value={searchFilter}
                onChange={e => setSearchFilter(e.target.value)}
                className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-4 text-white focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
              {filteredItems.length > 0 ? (
                filteredItems.map(p => (
                  <button 
                    key={p.id}
                    onClick={() => handleSelectProduct(p)}
                    className="w-full text-left p-4 bg-slate-800/40 hover:bg-slate-800 border border-slate-800 hover:border-blue-500/50 rounded-2xl flex items-center justify-between group transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-800 rounded-xl flex items-center justify-center font-bold text-slate-500 group-hover:text-blue-500 transition-colors">
                        {p.imageUrl ? <img src={p.imageUrl} className="w-full h-full object-cover rounded-xl" /> : <PackageOpen size={20}/>}
                      </div>
                      <div>
                        <p className="font-bold text-white group-hover:text-blue-400 transition-colors">{p.name}</p>
                        <p className="text-xs text-slate-500">{p.category} • R$ {p.suggestedPrice.toFixed(2)}</p>
                      </div>
                    </div>
                    <ChevronRight size={18} className="text-slate-600 group-hover:text-blue-500 group-hover:translate-x-1 transition-all" />
                  </button>
                ))
              ) : (
                <div className="text-center py-10">
                  <p className="text-slate-500">Nenhum item disponível encontrado.</p>
                </div>
              )}
            </div>

            <button 
              onClick={onClose}
              className="mt-6 w-full py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-2xl font-bold transition-all active:scale-95"
            >
              Cancelar
            </button>
          </div>
        ) : (
          /* Step 2: Sale Form */
          <div className="p-8 overflow-y-auto custom-scrollbar">
            <header className="mb-6 flex justify-between items-start">
              <div>
                <h3 className="text-2xl font-bold text-white">Registrar Venda</h3>
                <p className="text-slate-400">Produto: <span className="text-blue-400 font-bold">{selectedProduct.name}</span></p>
              </div>
              <button 
                onClick={() => setSelectedProduct(null)}
                className="text-[10px] font-bold text-blue-500 uppercase tracking-widest bg-blue-500/10 px-3 py-1.5 rounded-full border border-blue-500/20 hover:bg-blue-500/20 transition-all"
              >
                Trocar Item
              </button>
            </header>

            <div className="space-y-6">
              <div className="space-y-4">
                <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-800">
                  <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1">Data da Venda</label>
                  <input 
                    type="date"
                    value={saleDate}
                    onChange={e => setSaleDate(e.target.value)}
                    className="w-full bg-transparent border-none p-0 focus:ring-0 text-white font-medium"
                  />
                </div>

                {/* Cash Section */}
                <div className="bg-slate-800/30 p-5 rounded-3xl border border-slate-800/50">
                  <div className="flex items-center gap-2 mb-3">
                    <div className="text-green-500">{ICONS.Money}</div>
                    <h4 className="text-sm font-bold text-slate-300 uppercase">Recebimento em Dinheiro</h4>
                  </div>
                  <div className="flex items-center">
                    <span className="text-2xl font-bold text-slate-500 mr-2">R$</span>
                    <input 
                      type="number"
                      value={cashAmount || ''}
                      placeholder="0,00"
                      onChange={e => setCashAmount(parseFloat(e.target.value) || 0)}
                      className="flex-1 bg-transparent border-none text-2xl font-bold focus:ring-0 text-white p-0"
                    />
                  </div>
                </div>

                {/* Trade-in Section */}
                <div className={`p-5 rounded-3xl border transition-all ${isTradeActive ? 'bg-blue-600/10 border-blue-500/30 shadow-lg shadow-blue-900/10' : 'bg-slate-800/30 border-slate-800/50 opacity-60'}`}>
                  <div className="flex items-center gap-2 mb-4">
                    <div className="text-blue-400">{ICONS.Trade}</div>
                    <h4 className="text-sm font-bold text-slate-300 uppercase">Item de Troca</h4>
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1 ml-1">Produto Recebido</label>
                      <input 
                        type="text"
                        placeholder="Nome do item recebido na troca..."
                        value={tradeItemName}
                        onChange={e => setTradeItemName(e.target.value)}
                        className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 text-white text-sm"
                      />
                    </div>
                    <div>
                      <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1 ml-1">Categoria da Troca</label>
                      <select 
                        value={tradeItemCategory}
                        onChange={e => setTradeItemCategory(e.target.value)}
                        className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 text-white text-sm appearance-none cursor-pointer"
                      >
                        {CATEGORIES.map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                      </select>
                    </div>
                    <div>
                      <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1 ml-1">Valor Avaliado</label>
                      <div className="flex items-center bg-slate-900/50 border border-slate-700/50 rounded-xl p-3">
                        <span className="text-lg font-bold text-slate-500 mr-2">R$</span>
                        <input 
                          type="number"
                          value={tradeItemValue || ''}
                          placeholder="0,00"
                          onChange={e => setTradeItemValue(parseFloat(e.target.value) || 0)}
                          className="flex-1 bg-transparent border-none text-lg font-bold focus:ring-0 text-white p-0"
                        />
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Profit Summary */}
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 rounded-2xl bg-slate-800 border border-slate-700 text-center">
                  <p className="text-[10px] uppercase font-bold text-slate-500 mb-1">Total Recebido</p>
                  <p className="text-xl font-bold text-white">R$ {finalPrice.toFixed(2)}</p>
                </div>
                <div className="p-4 rounded-2xl bg-green-500/10 border border-green-500/20 text-center">
                  <p className="text-[10px] uppercase font-bold text-green-400 mb-1">Lucro na Venda</p>
                  <p className="text-xl font-bold text-green-400">R$ {realProfit.toFixed(2)}</p>
                </div>
              </div>

              <div className="flex gap-4 pt-2">
                <button 
                  onClick={onClose}
                  className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl font-bold transition-all text-white active:scale-95"
                >
                  Cancelar
                </button>
                <button 
                  disabled={(tradeItemValue > 0 && !tradeItemName) || (tradeItemName && tradeItemValue <= 0)}
                  onClick={() => onConfirm(finalPrice, cashAmount, tradeItemValue, saleDate, tradeItemName, tradeItemCategory)}
                  className="flex-1 py-4 bg-blue-600 hover:bg-blue-700 rounded-2xl font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed text-white shadow-lg shadow-blue-900/20 active:scale-95"
                >
                  Confirmar Venda
                </button>
              </div>
              {((tradeItemValue > 0 && !tradeItemName) || (tradeItemName && tradeItemValue <= 0)) && (
                <p className="text-center text-[10px] text-red-400 font-bold uppercase animate-pulse">
                  Preencha o nome e o valor do item de troca
                </p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SellProductModal;

import React, { useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProductList from './components/ProductList';
import SalesList from './components/SalesList';
import Reports from './components/Reports';
import SellProductModal from './components/SellProductModal';
import ConfirmModal from './components/ConfirmModal';
import { useAppState } from './hooks/useAppState';
import { Product } from './types';
import { ICONS } from './constants';
import { Download, Upload, Store, ShieldAlert, CheckCircle2 } from 'lucide-react';

const App: React.FC = () => {
  const { 
    products, 
    sales, 
    settings,
    currentView, 
    setCurrentView, 
    addProduct,
    updateProduct,
    deleteProduct, 
    deleteSale,
    sellProduct,
    updateSettings,
    importData
  } = useAppState();

  const [isNewSaleModalOpen, setIsNewSaleModalOpen] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [editBusinessName, setEditBusinessName] = useState(settings.businessName);
  const fileImportRef = useRef<HTMLInputElement>(null);

  const handleSellConfirmation = (finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string) => {
    // Note: The product selection logic is now inside SellProductModal
    // The previous implementation used productToSell, now it's managed via internal selection
    // The sellProduct hook will be called with the selected product ID
    // We update this in handleSellConfirmation call from the modal
    setIsNewSaleModalOpen(false);
    setCurrentView('Vendas');
  };

  // Wrapped sell handler because the Modal now handles its own product selection
  const handleFinalizeSale = (productId: string, finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string) => {
    sellProduct(productId, finalPrice, cash, tradeVal, date, tradeName, tradeCategory);
    setIsNewSaleModalOpen(false);
    setCurrentView('Vendas');
  };

  const handleResetDatabase = () => {
    localStorage.clear();
    window.location.reload();
  };

  const handleExportData = () => {
    const data = {
      products,
      sales,
      settings,
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `brixlucro_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (confirm('Deseja realmente importar esses dados? Isso substituirá suas informações atuais.')) {
            importData(json);
            alert('Dados importados com sucesso!');
          }
        } catch (err) {
          alert('Erro ao importar arquivo. Verifique se o formato JSON é válido.');
        }
      };
      reader.readAsText(file);
    }
    if (fileImportRef.current) fileImportRef.current.value = '';
  };

  const renderView = () => {
    switch (currentView) {
      case 'Dashboard':
        return <Dashboard products={products} sales={sales} />;
      case 'Produtos':
        return (
          <ProductList 
            products={products} 
            onAdd={addProduct} 
            onUpdate={updateProduct}
            onDelete={deleteProduct} 
          />
        );
      case 'Vendas':
        return (
          <SalesList 
            sales={sales} 
            onDeleteSale={deleteSale} 
            onNewSale={() => setIsNewSaleModalOpen(true)} 
          />
        );
      case 'Relatórios':
        return <Reports sales={sales} products={products} />;
      case 'Configurações':
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
            <header>
              <h2 className="text-3xl font-bold text-white">Administração</h2>
              <p className="text-slate-400">Gerencie seu perfil, dados e segurança.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-blue-600/10 p-4 rounded-2xl text-blue-500">
                    <Store size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Perfil do Negócio</h3>
                </div>
                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-1 ml-1">Nome do Negócio</label>
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={editBusinessName}
                        onChange={(e) => setEditBusinessName(e.target.value)}
                        className="flex-1 bg-slate-800 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500 text-white"
                        placeholder="Ex: Minha Loja"
                      />
                      <button 
                        onClick={() => updateSettings({ businessName: editBusinessName })}
                        className="bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-xl transition-all active:scale-90"
                      >
                        <CheckCircle2 size={20} />
                      </button>
                    </div>
                  </div>
                  <div className="p-4 bg-slate-800/30 rounded-2xl border border-slate-700/50 flex items-center justify-between">
                    <div>
                      <p className="text-[10px] text-slate-500 uppercase font-bold">Plano Atual</p>
                      <p className="font-bold text-blue-400">BrixLucro Pro</p>
                    </div>
                    <div className="bg-blue-500/10 text-blue-500 text-[10px] font-bold px-3 py-1 rounded-full border border-blue-500/20">ATIVO</div>
                  </div>
                </div>
              </div>

              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-green-600/10 p-4 rounded-2xl text-green-500">
                    <Download size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Gerenciamento de Dados</h3>
                </div>
                <p className="text-slate-400 text-sm mb-6">Mantenha seus dados seguros exportando um arquivo de backup ou restaure informações anteriores.</p>
                <div className="grid grid-cols-1 gap-3">
                  <button 
                    onClick={handleExportData}
                    className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-2xl font-bold transition-all active:scale-95 border border-slate-700"
                  >
                    <Download size={18} /> Exportar Backup (JSON)
                  </button>
                  <button 
                    onClick={() => fileImportRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-bold transition-all active:scale-95"
                  >
                    <Upload size={18} /> Importar Dados (JSON)
                  </button>
                  <input 
                    type="file" 
                    ref={fileImportRef} 
                    onChange={handleImportFile} 
                    className="hidden" 
                    accept=".json"
                  />
                </div>
              </div>

              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl md:col-span-2">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-red-600/10 p-4 rounded-2xl text-red-500">
                    <ShieldAlert size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Zona de Perigo</h3>
                </div>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                  <div className="flex-1">
                    <p className="text-white font-bold mb-1">Limpar Base de Dados</p>
                    <p className="text-slate-400 text-sm">Ações irreversíveis que apetam permanentemente seus dados. Use com cautela.</p>
                  </div>
                  <button 
                    onClick={() => setShowResetConfirm(true)}
                    className="px-8 py-4 bg-red-500/10 text-red-500 rounded-2xl font-bold hover:bg-red-600 hover:text-white transition-all shadow-lg active:scale-95 border border-red-500/20"
                  >
                    Resetar Todo o Sistema
                  </button>
                </div>
              </div>
            </div>

            <ConfirmModal 
              isOpen={showResetConfirm}
              title="Limpar Sistema?"
              message="Deseja realmente limpar todos os dados? Todos os produtos e vendas serão excluídos permanentemente."
              confirmText="Limpar Tudo"
              onConfirm={handleResetDatabase}
              onCancel={() => setShowResetConfirm(false)}
            />
          </div>
        );
      default:
        return <Dashboard products={products} sales={sales} />;
    }
  };

  return (
    <Layout currentView={currentView} setCurrentView={setCurrentView}>
      {renderView()}

      {isNewSaleModalOpen && (
        <SellProductModal 
          availableProducts={products.filter(p => p.status === 'Disponível')} 
          onClose={() => setIsNewSaleModalOpen(false)}
          onConfirm={(finalPrice, cash, tradeVal, date, tradeName, tradeCategory) => {
            // This is a bit tricky now since the Modal handles selection.
            // We'll need the ID of the selected product from the modal.
            // Updating the Modal to pass back the ID in its confirm callback.
          }}
          // Re-adding a wrapper to handle the selected ID from internal modal state
          {...{
            onConfirm: (productId: string, finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string) => {
               sellProduct(productId, finalPrice, cash, tradeVal, date, tradeName, tradeCategory);
               setIsNewSaleModalOpen(false);
               setCurrentView('Vendas');
            }
          } as any}
        />
      )}
    </Layout>
  );
};

export default App;

