                    <>
                      <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors mb-2" size={32} />
                      <span className="text-xs font-bold text-slate-500 uppercase">Alterar Foto</span>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={editFileInputRef} 
                    onChange={(e) => handleImageUpload(e, true)} 
                    className="hidden" 
                    accept="image/*" 
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input 
                    required
                    type="text" 
                    value={editingProduct.name}
                    onChange={e => setEditingProduct({...editingProduct, name: e.target.value})}
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                  <select 
                    value={editingProduct.category}
                    onChange={e => setEditingProduct({...editingProduct, category: e.target.value})}
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 appearance-none text-white"
                  >
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={editingProduct.purchasePrice || ''}
                      onChange={e => setEditingProduct({...editingProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${editingProduct.purchasePrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {editingProduct.purchasePrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      min="0.01"
                      value={editingProduct.suggestedPrice || ''}
                      onChange={e => setEditingProduct({...editingProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                      className={`w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white ${editingProduct.suggestedPrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                    />
                    {editingProduct.suggestedPrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button 
                    type="button"
                    onClick={() => setEditingProduct(null)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    disabled={!isEditingProductValid}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed py-4 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20 text-white"
                  >
                    Salvar Alterações
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Confirmation Modal */}
      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir o produto "${confirmDelete?.name}"? Esta ação removerá o item permanentemente do seu estoque.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default ProductList;

import React, { useState } from 'react';
import { Product } from '../types';
import { CATEGORIES, ICONS } from '../constants';
import { Search, ChevronRight, PackageOpen, AlertCircle } from 'lucide-react';

interface SellProductModalProps {
  availableProducts: Product[];
  onClose: () => void;
  onConfirm: (productId: string, finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string) => void;
}

const SellProductModal: React.FC<SellProductModalProps> = ({ availableProducts, onClose, onConfirm }) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchFilter, setSearchFilter] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const [cashAmount, setCashAmount] = useState<number>(0);
  const [tradeItemValue, setTradeItemValue] = useState<number>(0);
  const [tradeItemName, setTradeItemName] = useState<string>('');
  const [tradeItemCategory, setTradeItemCategory] = useState<string>(CATEGORIES[0]);
  const [saleDate, setSaleDate] = useState<string>(today);

  const filteredItems = availableProducts.filter(p => 
    p.name.toLowerCase().includes(searchFilter.toLowerCase()) || 
    p.category.toLowerCase().includes(searchFilter.toLowerCase())
  );

  const handleSelectProduct = (p: Product) => {
    setSelectedProduct(p);
    setCashAmount(p.suggestedPrice);
  };

  const finalPrice = (cashAmount || 0) + (tradeItemValue || 0);
  const realProfit = selectedProduct ? finalPrice - selectedProduct.purchasePrice : 0;
  const isTradeActive = tradeItemName.length > 0 || tradeItemValue > 0;

  // Validation for ensuring no sale below cost
  const isPriceValid = selectedProduct ? finalPrice >= selectedProduct.purchasePrice : true;
  const tradeValidationFailed = (tradeItemValue > 0 && !tradeItemName) || (tradeItemName && tradeItemValue <= 0);

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-slate-900 w-full max-w-lg rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">

        {/* Step 1: Selection */}
        {!selectedProduct ? (
          <div className="p-8 flex flex-col h-full overflow-hidden">
            <header className="mb-6">
              <h3 className="text-2xl font-bold text-white">Nova Venda</h3>
              <p className="text-slate-400">Selecione o item que deseja vender.</p>
            </header>

            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                placeholder="Buscar item disponível..."
                value={searchFilter}
                onChange={e => setSearchFilter(e.target.value)}
                className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-4 text-white focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
              {filteredItems.length > 0 ? (
                filteredItems.map(p => (
                  <button 
                    key={p.id}
                    onClick={() => handleSelectProduct(p)}
                    className="w-full text-left p-4 bg-slate-800/40 hover:bg-slate-800 border border-slate-800 hover:border-blue-500/50 rounded-2xl flex items-center justify-between group transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-800 rounded-xl flex items-center justify-center font-bold text-slate-500 group-hover:text-blue-500 transition-colors">
                        {p.imageUrl ? <img src={p.imageUrl} className="w-full h-full object-cover rounded-xl" /> : <PackageOpen size={20}/>}
                      </div>
                      <div>
                        <p className="font-bold text-white group-hover:text-blue-400 transition-colors">{p.name}</p>
                        <p className="text-xs text-slate-500">{p.category} • R$ {p.suggestedPrice.toFixed(2)}</p>
                      </div>
                    </div>
                    <ChevronRight size={18} className="text-slate-600 group-hover:text-blue-500 group-hover:translate-x-1 transition-all" />
                  </button>
