                  </p>
                  <p className={`text-xl font-bold ${isPriceValid ? 'text-green-400' : 'text-red-400'}`}>R$ {realProfit.toFixed(2)}</p>
                </div>
              </div>

              {!isPriceValid && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-1 duration-200">
                  <AlertCircle className="text-red-500 shrink-0" size={20} />
                  <p className="text-xs text-red-400 font-medium">
                    O valor total da venda deve ser igual ou superior ao preço de compra (R$ {selectedProduct?.purchasePrice.toFixed(2)}) para evitar prejuízo.
                  </p>
                </div>
              )}

              <div className="flex gap-4 pt-2">
                <button 
                  onClick={onClose}
                  className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl font-bold transition-all text-white active:scale-95"
                >
                  Cancelar
                </button>
                <button 
                  disabled={tradeValidationFailed || !isPriceValid}
                  onClick={() => onConfirm(selectedProduct!.id, finalPrice, cashAmount, tradeItemValue, saleDate, tradeItemName, tradeItemCategory)}
                  className="flex-1 py-4 bg-blue-600 hover:bg-blue-700 rounded-2xl font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed text-white shadow-lg shadow-blue-900/20 active:scale-95"
                >
                  Confirmar Venda
                </button>
              </div>
              {tradeValidationFailed && (
                <p className="text-center text-[10px] text-red-400 font-bold uppercase animate-pulse">
                  Preencha o nome e o valor do item de troca
                </p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

