                        required
                        type="number" 
                        step="0.01"
                        min="0.01"
                        value={editingProduct.purchasePrice || ''}
                        onChange={e => setEditingProduct({...editingProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                        className={`w-full bg-slate-800 rounded-2xl p-4 pl-12 border-none focus:ring-2 focus:ring-blue-500 font-bold text-red-500 ${editingProduct.purchasePrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                      />
                    </div>
                    {editingProduct.purchasePrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 font-bold text-slate-500">R$</span>
                      <input 
                        required
                        type="number" 
                        step="0.01"
                        min="0.01"
                        value={editingProduct.suggestedPrice || ''}
                        onChange={e => setEditingProduct({...editingProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                        className={`w-full bg-slate-800 rounded-2xl p-4 pl-12 border-none focus:ring-2 focus:ring-blue-500 font-bold text-green-500 ${editingProduct.suggestedPrice <= 0 ? 'ring-2 ring-red-500' : ''}`}
                      />
                    </div>
                    {editingProduct.suggestedPrice <= 0 && (
                      <p className="text-[10px] text-red-500 font-bold mt-1 ml-2 flex items-center gap-1"><AlertCircle size={10}/> Valor deve ser maior que zero</p>
                    )}
                  </div>
                </div>

                {/* Live Margin Calculation for Edit */}
                {editingProduct.purchasePrice > 0 && editingProduct.suggestedPrice > 0 && (
                  <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 flex items-center justify-between animate-in fade-in zoom-in-95 duration-200">
                    <div className="flex items-center gap-2">
                      <TrendingUp size={16} className="text-green-500" />
                      <span className="text-xs font-bold text-slate-400 uppercase">Nova Margem</span>
                    </div>
                    <span className={`text-xl font-black ${calculateMargin(editingProduct.purchasePrice, editingProduct.suggestedPrice) >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                      {calculateMargin(editingProduct.purchasePrice, editingProduct.suggestedPrice).toFixed(1)}%
                    </span>
                  </div>
                )}

                <div className="flex gap-4 mt-8">
                  <button 
                    type="button"
                    onClick={() => setEditingProduct(null)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    disabled={!isEditingProductValid}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed py-4 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20 text-white"
                  >
                    Salvar Alterações
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Confirmation Modal */}
      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir o produto "${confirmDelete?.name}"? Esta ação removerá o item permanentemente do seu estoque.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

