          <p className="text-slate-400 font-medium">Resumo de desempenho para o período selecionado.</p>
        </div>

        <div className="flex items-center gap-2 bg-slate-800 p-2 rounded-2xl border border-slate-700 shadow-inner">
          <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-900 rounded-xl">
             <Calendar size={16} className="text-blue-500" />
             <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              className="bg-transparent border-none text-sm font-bold focus:ring-0 cursor-pointer text-white appearance-none pr-4"
            >
              {MONTHS.map((m, i) => (
                <option key={m} value={i} className="bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
          <div className="w-px h-6 bg-slate-700"></div>
          <select 
            value={selectedYear}
            onChange={(e) => setSelectedYear(parseInt(e.target.value))}
            className="bg-transparent border-none text-sm font-bold px-3 py-1.5 focus:ring-0 cursor-pointer text-white appearance-none"
          >
            {years.map(y => (
              <option key={y} value={y} className="bg-slate-900">{y}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Primary KPI Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* Receita Total */}
        <div className="bg-slate-900 p-6 rounded-[2rem] border border-slate-800 shadow-xl relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 text-blue-500/10 group-hover:scale-110 transition-transform duration-500">
            <DollarSign size={120} />
          </div>
          <div className="relative z-10">
            <div className="bg-blue-500/10 w-12 h-12 rounded-2xl flex items-center justify-center text-blue-500 mb-4 shadow-inner">
              <DollarSign size={24} />
            </div>
            <p className="text-slate-400 text-xs font-black uppercase tracking-widest mb-1">Receita Bruta</p>
            <h3 className="text-2xl font-black text-white">R$ {totalSold.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
          </div>
        </div>

        {/* Lucro Líquido */}
        <div className="bg-slate-900 p-6 rounded-[2rem] border border-slate-800 shadow-xl relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 text-green-500/10 group-hover:scale-110 transition-transform duration-500">
            <TrendingUp size={120} />
          </div>
          <div className="relative z-10">
            <div className="bg-green-500/10 w-12 h-12 rounded-2xl flex items-center justify-center text-green-500 mb-4 shadow-inner">
