import React, { useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProductList from './components/ProductList';
import SalesList from './components/SalesList';
import Reports from './components/Reports';
import SellProductModal from './components/SellProductModal';
import ConfirmModal from './components/ConfirmModal';
import { useAppState } from './hooks/useAppState';
import { Product } from './types';
import { ICONS } from './constants';
import { Download, Upload, Store, ShieldAlert, CheckCircle2 } from 'lucide-react';

const App: React.FC = () => {
  const { 
    products, 
    sales, 
    settings,
    currentView, 
    setCurrentView, 
    addProduct,
    updateProduct,
    deleteProduct, 
    deleteSale,
    sellProduct,
    updateSettings,
    importData
  } = useAppState();

  const [isNewSaleModalOpen, setIsNewSaleModalOpen] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [editBusinessName, setEditBusinessName] = useState(settings.businessName);
  const fileImportRef = useRef<HTMLInputElement>(null);

  const handleFinalizeSale = (productId: string, finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string) => {
    sellProduct(productId, finalPrice, cash, tradeVal, date, tradeName, tradeCategory);
    setIsNewSaleModalOpen(false);
    setCurrentView('Vendas');
  };

  const handleResetDatabase = () => {
    localStorage.clear();
    window.location.reload();
  };

  const handleExportData = () => {
    const data = {
      products,
      sales,
      settings,
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `briquepro_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (confirm('Deseja realmente importar esses dados? Isso substituirá suas informações atuais.')) {
            importData(json);
            alert('Dados importados com sucesso!');
          }
        } catch (err) {
          alert('Erro ao importar arquivo. Verifique se o formato JSON é válido.');
        }
      };
      reader.readAsText(file);
    }
    if (fileImportRef.current) fileImportRef.current.value = '';
  };

  const renderView = () => {
    switch (currentView) {
      case 'Dashboard':
        return <Dashboard products={products} sales={sales} />;
      case 'Produtos':
        return (
          <ProductList 
            products={products} 
            onAdd={addProduct} 
            onUpdate={updateProduct}
            onDelete={deleteProduct} 
          />
        );
      case 'Vendas':
        return (
          <SalesList 
            sales={sales} 
            onDeleteSale={deleteSale} 
            onNewSale={() => setIsNewSaleModalOpen(true)} 
          />
        );
      case 'Relatórios':
        return <Reports sales={sales} products={products} />;
      case 'Configurações':
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
            <header>
              <h2 className="text-3xl font-bold text-white">Administração</h2>
              <p className="text-slate-400">Gerencie seu perfil, dados e segurança.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-blue-600/10 p-4 rounded-2xl text-blue-500">
                    <Store size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Perfil do Negócio</h3>
                </div>
                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-1 ml-1">Nome do Negócio</label>
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={editBusinessName}
                        onChange={(e) => setEditBusinessName(e.target.value)}
                        className="flex-1 bg-slate-800 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500 text-white"
                        placeholder="Ex: Minha Loja"
                      />
                      <button 
                        onClick={() => updateSettings({ businessName: editBusinessName })}
                        className="bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-xl transition-all active:scale-90"
                      >
                        <CheckCircle2 size={20} />
                      </button>
                    </div>
                  </div>
                  <div className="p-4 bg-slate-800/30 rounded-2xl border border-slate-700/50 flex items-center justify-between">
                    <div>
                      <p className="text-[10px] text-slate-500 uppercase font-bold">Plano Atual</p>
                      <p className="font-bold text-blue-400">BriquePro Pro</p>
                    </div>
                    <div className="bg-blue-500/10 text-blue-500 text-[10px] font-bold px-3 py-1 rounded-full border border-blue-500/20">ATIVO</div>
                  </div>
                </div>
              </div>

              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-green-600/10 p-4 rounded-2xl text-green-500">
                    <Download size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Gerenciamento de Dados</h3>
                </div>
                <p className="text-slate-400 text-sm mb-6">Mantenha seus dados seguros exportando um arquivo de backup ou restaure informações anteriores.</p>
                <div className="grid grid-cols-1 gap-3">
                  <button 
                    onClick={handleExportData}
                    className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-2xl font-bold transition-all active:scale-95 border border-slate-700"
                  >
                    <Download size={18} /> Exportar Backup (JSON)
                  </button>
                  <button 
                    onClick={() => fileImportRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-bold transition-all active:scale-95"
                  >
                    <Upload size={18} /> Importar Dados (JSON)
                  </button>
                  <input 
                    type="file" 
                    ref={fileImportRef} 
                    onChange={handleImportFile} 
                    className="hidden" 
                    accept=".json"
                  />
                </div>
              </div>

              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl md:col-span-2">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-red-600/10 p-4 rounded-2xl text-red-500">
                    <ShieldAlert size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Zona de Perigo</h3>
                </div>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                  <div className="flex-1">
                    <p className="text-white font-bold mb-1">Limpar Base de Dados</p>
                    <p className="text-slate-400 text-sm">Ações irreversíveis que apetam permanentemente seus dados. Use com cautela.</p>
                  </div>
                  <button 
                    onClick={() => setShowResetConfirm(true)}
                    className="px-8 py-4 bg-red-500/10 text-red-500 rounded-2xl font-bold hover:bg-red-600 hover:text-white transition-all shadow-lg active:scale-95 border border-red-500/20"
                  >
                    Resetar Todo o Sistema
                  </button>
                </div>
              </div>
            </div>

            <ConfirmModal 
              isOpen={showResetConfirm}
              title="Limpar Sistema?"
              message="Deseja realmente limpar todos os dados? Todos os produtos e vendas serão excluídos permanentemente."
              confirmText="Limpar Tudo"
              onConfirm={handleResetDatabase}
              onCancel={() => setShowResetConfirm(false)}
            />
          </div>
        );
      default:
        return <Dashboard products={products} sales={sales} />;
    }
  };

  return (
    <Layout currentView={currentView} setCurrentView={setCurrentView}>
      {renderView()}

      {isNewSaleModalOpen && (
        <SellProductModal 
          availableProducts={products.filter(p => p.status === 'Disponível')} 
          onClose={() => setIsNewSaleModalOpen(false)}
          onConfirm={handleFinalizeSale}
        />
      )}
    </Layout>
  );
};

export default App;

import { useState, useEffect, useCallback } from 'react';
import { Product, Sale, View } from '../types';

const STORAGE_KEY_PRODUCTS = 'brixlucro_products';
const STORAGE_KEY_SALES = 'brixlucro_sales';
const STORAGE_KEY_SETTINGS = 'brixlucro_settings';

const INITIAL_PRODUCTS: Product[] = [
  { id: '1', name: 'iPhone 13 128GB', category: 'Celular', purchasePrice: 3500, suggestedPrice: 4800, status: 'Disponível', createdAt: new Date().toISOString() },
  { id: '2', name: 'Camiseta Premium XL', category: 'Vestuário', purchasePrice: 45, suggestedPrice: 120, status: 'Disponível', createdAt: new Date().toISOString() },
  { id: '3', name: 'Fone Bluetooth Pro', category: 'Acessórios', purchasePrice: 180, suggestedPrice: 350, status: 'Vendido', createdAt: new Date().toISOString() },
];

const INITIAL_SALES: Sale[] = [
  { 
    id: 's1', 
    productId: '3', 
    productName: 'Fone Bluetooth Pro', 
    date: new Date().toISOString(), 
    finalPrice: 330, 
    cashAmount: 330, 
    tradeItemValue: 0, 
    purchasePrice: 180, 
    profit: 150 
  }
];

export const useAppState = () => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PRODUCTS);
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SALES);
    return saved ? JSON.parse(saved) : INITIAL_SALES;
  });

  const [settings, setSettings] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SETTINGS);
    return saved ? JSON.parse(saved) : { businessName: 'Meu Negócio' };
  });

  const [currentView, setCurrentView] = useState<View>('Dashboard');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PRODUCTS, JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SALES, JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(settings));
  }, [settings]);

  const addProduct = (p: Omit<Product, 'id' | 'createdAt' | 'status'>) => {
    const newProduct: Product = {
      ...p,
      id: crypto.randomUUID(),
      status: 'Disponível',
      createdAt: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSale = (id: string) => {
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const updateSettings = (newSettings: any) => {
    setSettings(prev => ({ ...prev, ...newSettings }));
  };

  const importData = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.settings) setSettings(data.settings);
  };

  const sellProduct = (
    productId: string, 
    finalPrice: number, 
    cashAmount: number, 
    tradeItemValue: number, 
    date: string,
    tradeName?: string,
    tradeCategory?: string,
    tradeSuggestedPrice?: number
  ) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    const newSale: Sale = {
      id: crypto.randomUUID(),
      productId: product.id,
      productName: product.name,
      date: date,
      finalPrice: finalPrice,
      cashAmount: cashAmount,
      tradeItemValue: tradeItemValue,
      tradeItemName: tradeName,
      purchasePrice: product.purchasePrice,
      profit: finalPrice - product.purchasePrice
    };

    setProducts(prev => prev.map(p => p.id === productId ? { ...p, status: 'Vendido' } : p));
    setSales(prev => [newSale, ...prev]);

    // Cadastro automático do item recebido na troca
    if (tradeItemValue > 0 && tradeName) {
      const tradedProduct: Product = {
        id: crypto.randomUUID(),
        name: tradeName,
        category: tradeCategory || 'Troca',
        purchasePrice: tradeItemValue,
        // Usa o preço sugerido informado ou calcula 50% de margem por padrão
        suggestedPrice: tradeSuggestedPrice || (tradeItemValue * 1.5),
        status: 'Disponível',
        createdAt: new Date().toISOString()
      };
      setProducts(prev => [tradedProduct, ...prev]);
    }
  };

  return {
    products,
    sales,
    settings,
    currentView,
    setCurrentView,
    addProduct,
    updateProduct,
    deleteProduct,
    deleteSale,
    sellProduct,
    updateSettings,
    importData
  };
};

