      createdAt: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSale = (id: string) => {
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const updateSettings = (newSettings: any) => {
    setSettings(prev => ({ ...prev, ...newSettings }));
  };

  const importData = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.settings) setSettings(data.settings);
  };

  const sellProduct = (
    productId: string, 
    finalPrice: number, 
    cashAmount: number, 
    tradeItemValue: number, 
    date: string,
    tradeName?: string,
    tradeCategory?: string,
    tradeSuggestedPrice?: number
  ) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    const newSale: Sale = {
      id: crypto.randomUUID(),
      productId: product.id,
      productName: product.name,
      date: date,
      finalPrice: finalPrice,
      cashAmount: cashAmount,
      tradeItemValue: tradeItemValue,
      tradeItemName: tradeName,
      purchasePrice: product.purchasePrice,
      profit: finalPrice - product.purchasePrice
    };

    setSales(prev => [newSale, ...prev]);

    // Reduzir quantidade e atualizar status
    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        const newQty = Math.max(0, p.quantity - 1);
        return { 
          ...p, 
          quantity: newQty,
          status: newQty === 0 ? 'Vendido' : 'Disponível'
        };
      }
      return p;
    }));

    if (tradeItemValue > 0 && tradeName) {
      const tradedProduct: Product = {
        id: crypto.randomUUID(),
        name: tradeName,
        category: tradeCategory || 'Troca',
        purchasePrice: tradeItemValue,
        suggestedPrice: tradeSuggestedPrice || (tradeItemValue * 1.5),
        quantity: 1, // Itens de troca entram com 1 unidade por padrão
        status: 'Disponível',
        createdAt: new Date().toISOString()
      };
      setProducts(prev => [tradedProduct, ...prev]);
    }
  };

  return {
    products,
    sales,
    settings,
    currentView,
    setCurrentView,
    addProduct,
    updateProduct,
    deleteProduct,
    deleteSale,
    sellProduct,
    updateSettings,
    importData
  };
};

import React, { useState, useRef } from 'react';
import { Product, ProductStatus } from '../types';
import { ICONS, CATEGORIES } from '../constants';
import ConfirmModal from './ConfirmModal';
import { Camera, AlertCircle, TrendingUp, DollarSign, Layers } from 'lucide-react';

interface ProductListProps {
  products: Product[];
  onAdd: (p: any) => void;
  onUpdate: (p: Product) => void;
  onDelete: (id: string) => void;
}

const ProductList: React.FC<ProductListProps> = ({ products, onAdd, onUpdate, onDelete }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, name: string } | null>(null);
  const [filter, setFilter] = useState<string>('');
  const [categoryFilter, setCategoryFilter] = useState<string>('Todas');
  const [activeTab, setActiveTab] = useState<ProductStatus>('Disponível');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  const [newProduct, setNewProduct] = useState({
    name: '',
    category: CATEGORIES[0],
    purchasePrice: 0,
    suggestedPrice: 0,
    quantity: 1,
    imageUrl: ''
  });

  const calculateProfitValue = (purchase: number, suggested: number) => suggested - purchase;
  const calculateMargin = (purchase: number, suggested: number) => {
    if (purchase <= 0) return 0;
    return ((suggested - purchase) / purchase) * 100;
  };

  const isNewProductValid = newProduct.name.trim() !== '' && 
                            newProduct.purchasePrice > 0 && 
                            newProduct.suggestedPrice > 0 &&
                            newProduct.quantity > 0;

  const isEditingProductValid = editingProduct && 
                                editingProduct.name.trim() !== '' && 
                                editingProduct.purchasePrice > 0 && 
                                editingProduct.suggestedPrice > 0 &&
                                editingProduct.quantity >= 0;

  const filteredProducts = products.filter(p => {
    const matchesName = p.name.toLowerCase().includes(filter.toLowerCase());
    const matchesCat = categoryFilter === 'Todas' || p.category === categoryFilter;
    const matchesStatus = p.status === activeTab;
    return matchesName && matchesCat && matchesStatus;
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (isEdit && editingProduct) {
          setEditingProduct({ ...editingProduct, imageUrl: reader.result as string });
        } else {
          setNewProduct({ ...newProduct, imageUrl: reader.result as string });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isNewProductValid) {
      onAdd(newProduct);
      setNewProduct({ name: '', category: CATEGORIES[0], purchasePrice: 0, suggestedPrice: 0, quantity: 1, imageUrl: '' });
      setShowAddModal(false);
    }
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isEditingProductValid) {
      const status = editingProduct!.quantity === 0 ? 'Vendido' : 'Disponível';
      onUpdate({ ...editingProduct!, status });
      setEditingProduct(null);
    }
  };

  const handleConfirmDelete = () => {
    if (confirmDelete) {
      onDelete(confirmDelete.id);
      setConfirmDelete(null);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight">Produtos</h2>
          <p className="text-slate-400">Gerencie seu estoque e visualize seus lucros.</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-900/20 transition-all active:scale-95"
        >
          {ICONS.Plus} Novo Produto
        </button>
      </header>

      <div className="flex bg-slate-800/50 p-1.5 rounded-2xl border border-slate-700 max-w-fit">
        <button
          onClick={() => setActiveTab('Disponível')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'Disponível' 
            ? 'bg-blue-600 text-white shadow-lg' 
            : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          Disponíveis ({products.filter(p => p.status === 'Disponível').length})
        </button>
        <button
          onClick={() => setActiveTab('Vendido')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'Vendido' 
            ? 'bg-red-600 text-white shadow-lg' 
            : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          Vendidos ({products.filter(p => p.status === 'Vendido').length})
        </button>
      </div>

      <div className="flex flex-col sm:flex-row gap-3">
        <div className="flex-1 relative">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">{ICONS.Filter}</span>
          <input 
            type="text" 
            placeholder="Buscar por nome..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all text-white"
          />
        </div>
        <select 
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
          className="bg-slate-800 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-blue-500 appearance-none text-white min-w-[150px]"
        >
          <option>Todas</option>
          {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredProducts.map(p => {
          const profitValue = calculateProfitValue(p.purchasePrice, p.suggestedPrice);
          const totalProfitValue = profitValue * p.quantity;
          const profitPerc = calculateMargin(p.purchasePrice, p.suggestedPrice);
          const isSold = p.status === 'Vendido';

          return (
            <div key={p.id} className={`bg-card rounded-3xl border ${isSold ? 'border-slate-800 opacity-75' : 'border-slate-800'} overflow-hidden shadow-xl transition-all hover:border-slate-700 flex flex-col`}>
              <div className="relative h-48 bg-slate-800 flex items-center justify-center overflow-hidden">
                {p.imageUrl ? (
                  <img src={p.imageUrl} alt={p.name} className="w-full h-full object-cover" />
                ) : (
                  <div className="text-slate-600 flex flex-col items-center gap-2">
                    {ICONS.Produtos}
                    <span className="text-[10px] uppercase font-bold tracking-widest">Sem Foto</span>
                  </div>
                )}
                <div className="absolute top-4 left-4 flex gap-2">
                  <span className={`text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-full border ${
                    isSold 
                    ? 'bg-red-500/20 text-red-400 border-red-500/30' 
                    : 'bg-green-500/20 text-green-400 border-green-500/30'
                  } backdrop-blur-md`}>
                    {p.status}
                  </span>
                  {!isSold && (
                    <span className="bg-blue-600/40 text-white text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-full border border-blue-500/30 backdrop-blur-md flex items-center gap-1">
                      <Layers size={10} /> {p.quantity} un.
                    </span>
                  )}
                </div>

                <div className="absolute top-4 right-4 flex gap-2">
                  <button 
                    onClick={() => setEditingProduct(p)}
                    className="p-2 bg-slate-900/60 text-white rounded-xl hover:bg-slate-900 transition-all backdrop-blur-md"
                  >
                    {ICONS.Edit}
                  </button>
                  <button 
                    onClick={() => setConfirmDelete({ id: p.id, name: p.name })}
                    className="p-2 bg-red-500/10 text-red-500 hover:bg-red-500 transition-all rounded-xl backdrop-blur-md"
                  >
                    {ICONS.Trash}
                  </button>
                </div>
              </div>

              <div className="p-6 flex-1">
                <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mb-1">{p.category}</p>
                <h3 className="text-xl font-bold mb-4 truncate text-white">{p.name}</h3>

                <div className="space-y-3">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Unitário:</span>
                    <span className="font-bold text-slate-300">R$ {p.purchasePrice.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Venda:</span>
                    <span className="font-bold text-blue-400">R$ {p.suggestedPrice.toFixed(2)}</span>
                  </div>
                  <div className="pt-3 border-t border-slate-800 space-y-2">
                    <div className="flex justify-between items-center">
                      <span className="text-xs text-slate-500 font-semibold uppercase">Lucro Unitário</span>
                      <span className={`text-sm font-bold ${profitValue >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                        R$ {profitValue.toFixed(2)} ({profitPerc.toFixed(0)}%)
                      </span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-xs text-slate-500 font-semibold uppercase">Lucro Total Potencial</span>
                      <span className={`text-lg font-black ${totalProfitValue >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                        R$ {totalProfitValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  </div>
                </div>
              </div>

              {isSold && (
                <div className="p-4 bg-slate-800/30 text-center">
                  <div className="py-2 text-xs text-slate-500 italic rounded-xl bg-slate-800/50">
                    Estoque Zerado
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {filteredProducts.length === 0 && (
        <div className="p-20 text-center bg-slate-800/30 rounded-[3rem] border border-dashed border-slate-700">
          <p className="text-slate-500 font-medium">Nenhum produto encontrado nesta categoria.</p>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            <div className="p-8 overflow-y-auto">
              <h3 className="text-2xl font-bold mb-6 text-white tracking-tight">Novo Produto</h3>
              <form onSubmit={handleSubmit} className="space-y-5">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden"
                >
                  {newProduct.imageUrl ? (
                    <img src={newProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors mb-2" size={32} />
                      <span className="text-xs font-bold text-slate-500 uppercase">Subir Foto</span>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={(e) => handleImageUpload(e, false)} 
                    className="hidden" 
                    accept="image/*" 
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input 
                    required
                    type="text" 
                    value={newProduct.name}
                    onChange={e => setNewProduct({...newProduct, name: e.target.value})}
                    placeholder="Ex: Tênis Air Max"
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                    <select 
                      value={newProduct.category}
                      onChange={e => setNewProduct({...newProduct, category: e.target.value})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 appearance-none text-white"
                    >
                      {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Quantidade</label>
                    <input 
                      required
                      type="number" 
                      min="1"
                      value={newProduct.quantity}
                      onChange={e => setNewProduct({...newProduct, quantity: parseInt(e.target.value) || 0})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <div className="relative">
                       <span className="absolute left-4 top-1/2 -translate-y-1/2 font-bold text-slate-500">R$</span>
                       <input 
                        required
                        type="number" 
                        step="0.01"
                        min="0.01"
                        value={newProduct.purchasePrice || ''}
                        onChange={e => setNewProduct({...newProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                        className="w-full bg-slate-800 rounded-2xl p-4 pl-12 border-none focus:ring-2 focus:ring-blue-500 text-white font-bold"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 font-bold text-slate-500">R$</span>
                      <input 
                        required
                        type="number" 
                        step="0.01"
                        min="0.01"
                        value={newProduct.suggestedPrice || ''}
                        onChange={e => setNewProduct({...newProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                        className="w-full bg-slate-800 rounded-2xl p-4 pl-12 border-none focus:ring-2 focus:ring-blue-500 text-white font-bold"
                      />
                    </div>
                  </div>
                </div>

                {newProduct.purchasePrice > 0 && newProduct.suggestedPrice > 0 && (
                  <div className="bg-slate-800/50 p-5 rounded-3xl border border-slate-700 space-y-3 animate-in fade-in zoom-in-95 duration-200">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-2 text-slate-400">
                        <TrendingUp size={16} />
                        <span className="text-[10px] font-bold uppercase tracking-wider">Margem</span>
                      </div>
                      <span className={`font-black ${calculateProfitValue(newProduct.purchasePrice, newProduct.suggestedPrice) >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                        {calculateMargin(newProduct.purchasePrice, newProduct.suggestedPrice).toFixed(1)}%
                      </span>
                    </div>
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-2 text-slate-400">
                        <DollarSign size={16} />
                        <span className="text-[10px] font-bold uppercase tracking-wider">Lucro Total Lote</span>
                      </div>
                      <span className={`text-xl font-black ${calculateProfitValue(newProduct.purchasePrice, newProduct.suggestedPrice) >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                        R$ {(calculateProfitValue(newProduct.purchasePrice, newProduct.suggestedPrice) * newProduct.quantity).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  </div>
                )}

                <div className="flex gap-4 mt-8">
                  <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white">Cancelar</button>
                  <button type="submit" disabled={!isNewProductValid} className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 py-4 rounded-2xl font-bold transition-all text-white shadow-lg shadow-blue-900/20">Salvar Item</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            <div className="p-8 overflow-y-auto">
              <h3 className="text-2xl font-bold mb-6 text-white tracking-tight">Editar Produto</h3>
              <form onSubmit={handleEditSubmit} className="space-y-5">
                <div onClick={() => editFileInputRef.current?.click()} className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex items-center justify-center cursor-pointer overflow-hidden">
                  {editingProduct.imageUrl ? <img src={editingProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" /> : <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors" size={32} />}
                  <input type="file" ref={editFileInputRef} onChange={(e) => handleImageUpload(e, true)} className="hidden" accept="image/*" />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input required type="text" value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-800 rounded-2xl p-4 border-none text-white" />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                    <select value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-slate-800 rounded-2xl p-4 border-none text-white">
                      {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Quantidade</label>
                    <input required type="number" min="0" value={editingProduct.quantity} onChange={e => setEditingProduct({...editingProduct, quantity: parseInt(e.target.value) || 0})} className="w-full bg-slate-800 rounded-2xl p-4 border-none text-white" />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Compra</label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 font-bold text-slate-500">R$</span>
                      <input required type="number" step="0.01" value={editingProduct.purchasePrice || ''} onChange={e => setEditingProduct({...editingProduct, purchasePrice: parseFloat(e.target.value) || 0})} className="w-full bg-slate-800 rounded-2xl p-4 pl-12 border-none text-white font-bold" />
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda</label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 font-bold text-slate-500">R$</span>
                      <input required type="number" step="0.01" value={editingProduct.suggestedPrice || ''} onChange={e => setEditingProduct({...editingProduct, suggestedPrice: parseFloat(e.target.value) || 0})} className="w-full bg-slate-800 rounded-2xl p-4 pl-12 border-none text-white font-bold" />
                    </div>
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button type="button" onClick={() => setEditingProduct(null)} className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white">Cancelar</button>
                  <button type="submit" disabled={!isEditingProductValid} className="flex-1 bg-blue-600 hover:bg-blue-700 py-4 rounded-2xl font-bold transition-all text-white shadow-lg shadow-blue-900/20">Salvar Alterações</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir o produto "${confirmDelete?.name}"? Esta ação removerá o item permanentemente do seu estoque.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default ProductList;

import React, { useState } from 'react';
import { Product, Sale } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ICONS } from '../constants';

interface DashboardProps {
  products: Product[];
  sales: Sale[];
}

const MONTHS = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const Dashboard: React.FC<DashboardProps> = ({ products, sales }) => {
  const now = new Date();
  const [selectedMonth, setSelectedMonth] = useState(now.getMonth());
  const [selectedYear, setSelectedYear] = useState(now.getFullYear());

  const years = Array.from({ length: 2030 - 2021 + 1 }, (_, i) => 2022 + i);

  const filteredSales = sales.filter(s => {
    const d = new Date(s.date);
    return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
  });

  const totalSold = filteredSales.reduce((acc, s) => acc + s.finalPrice, 0);
  const totalProfit = filteredSales.reduce((acc, s) => acc + s.profit, 0);
  const totalPurchase = filteredSales.reduce((acc, s) => acc + s.purchasePrice, 0);

  const profitPercentage = totalPurchase > 0 ? (totalProfit / totalPurchase) * 100 : 0;
  const itemsSold = filteredSales.length;

  // Calcula total de unidades disponíveis (soma das quantidades)
  const availableItemsCount = products
    .filter(p => p.status === 'Disponível')
    .reduce((acc, p) => acc + p.quantity, 0);

  const data = filteredSales.slice(0, 7).reverse().map((s, i) => ({
    name: `Venda ${i + 1}`,
    valor: s.finalPrice,
    lucro: s.profit
  }));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-bold">Dashboard</h2>
          <p className="text-slate-400">Desempenho em {MONTHS[selectedMonth]} de {selectedYear}.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-2 bg-slate-800/80 p-1.5 rounded-2xl border border-slate-700">
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              className="bg-transparent border-none text-sm font-semibold px-3 py-1.5 focus:ring-0 cursor-pointer text-white"
            >
              {MONTHS.map((m, i) => (
                <option key={m} value={i} className="bg-slate-900">{m}</option>
              ))}
            </select>
            <div className="w-px h-4 bg-slate-700"></div>
            <select 
              value={selectedYear}
              onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              className="bg-transparent border-none text-sm font-semibold px-3 py-1.5 focus:ring-0 cursor-pointer text-white"
            >
              {years.map(y => (
                <option key={y} value={y} className="bg-slate-900">{y}</option>
              ))}
            </select>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="bg-blue-500/10 p-3 rounded-2xl text-blue-500 w-fit mb-4">{ICONS.Money}</div>
          <p className="text-slate-400 text-sm font-medium mb-1">Vendido no Período</p>
          <h3 className="text-2xl font-bold">R$ {totalSold.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="bg-green-500/10 p-3 rounded-2xl text-green-500 w-fit mb-4">{ICONS.Profit}</div>
          <p className="text-slate-400 text-sm font-medium mb-1">Lucro no Período</p>
          <h3 className="text-2xl font-bold">R$ {totalProfit.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="bg-purple-500/10 p-3 rounded-2xl text-purple-500 w-fit mb-4">{ICONS.Produtos}</div>
          <p className="text-slate-400 text-sm font-medium mb-1">Unidades Vendidas</p>
          <h3 className="text-2xl font-bold">{itemsSold} <span className="text-slate-500 text-base font-normal">un.</span></h3>
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl">
          <div className="bg-orange-500/10 p-3 rounded-2xl text-orange-500 w-fit mb-4">{ICONS.Relatórios}</div>
          <p className="text-slate-400 text-sm font-medium mb-1">Margem Média</p>
          <h3 className="text-2xl font-bold">{profitPercentage.toFixed(1)}%</h3>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl h-[400px]">
          <h4 className="text-lg font-bold mb-6">Últimas Vendas</h4>
          {data.length > 0 ? (
            <ResponsiveContainer width="100%" height="80%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `R$${val}`} />
                <Tooltip contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', borderRadius: '12px' }} itemStyle={{ color: '#f8fafc' }} />
                <Bar dataKey="valor" radius={[4, 4, 0, 0]}>
                  {data.map((entry, index) => <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#3b82f6' : '#22c55e'} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="h-4/5 flex flex-col items-center justify-center text-slate-500 gap-2"><p className="text-sm font-medium">Sem vendas para este período</p></div>
          )}
        </div>

        <div className="bg-card p-6 rounded-3xl border border-slate-800 shadow-xl overflow-hidden">
          <div className="flex justify-between items-center mb-6">
            <h4 className="text-lg font-bold">Resumo Estoque ({availableItemsCount} un.)</h4>
          </div>
          <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
            {products.filter(p => p.status === 'Disponível').length > 0 ? (
              products.filter(p => p.status === 'Disponível').map(p => (
                <div key={p.id} className="flex items-center justify-between p-4 bg-slate-800/30 rounded-2xl border border-slate-700/50">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-slate-700 rounded-xl flex items-center justify-center font-bold text-slate-400">{p.name.charAt(0)}</div>
                    <div>
                      <p className="font-semibold text-white">{p.name}</p>
                      <p className="text-xs text-slate-500">{p.quantity} unidades disponíveis</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-bold text-blue-400">R$ {p.suggestedPrice.toFixed(2)}</p>
                  </div>
                </div>
              ))
            ) : (
              <div className="p-8 text-center text-slate-500"><p className="text-sm">Nenhum produto disponível</p></div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

export type ProductStatus = 'Disponível' | 'Vendido';

export interface Product {
  id: string;
  name: string;
  category: string;
  purchasePrice: number;
  suggestedPrice: number;
  quantity: number;
  status: ProductStatus;
  createdAt: string;
  imageUrl?: string;
}

export interface Sale {
  id: string;
  productId: string;
  productName: string;
  quantity: number; // Quantidade vendida nesta transação
  date: string;
  finalPrice: number; // Total value of sale (Cash + Trade)
  cashAmount: number;
  tradeItemValue: number;
  tradeItemName?: string;
  purchasePrice: number; // Snapshot of unit cost at time of sale
  profit: number; // (finalPrice - (purchasePrice * quantity))
}

export type View = 'Dashboard' | 'Produtos' | 'Vendas' | 'Relatórios' | 'Configurações';

import { useState, useEffect, useCallback } from 'react';
import { Product, Sale, View } from '../types';

const STORAGE_KEY_PRODUCTS = 'brixlucro_products';
const STORAGE_KEY_SALES = 'brixlucro_sales';
const STORAGE_KEY_SETTINGS = 'brixlucro_settings';

const INITIAL_PRODUCTS: Product[] = [];
const INITIAL_SALES: Sale[] = [];

export const useAppState = () => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PRODUCTS);
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SALES);
    return saved ? JSON.parse(saved) : INITIAL_SALES;
  });

  const [settings, setSettings] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY_SETTINGS);
    return saved ? JSON.parse(saved) : { businessName: 'Meu Negócio' };
  });

  const [currentView, setCurrentView] = useState<View>('Dashboard');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PRODUCTS, JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SALES, JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(settings));
  }, [settings]);

  const addProduct = (p: Omit<Product, 'id' | 'createdAt' | 'status'>) => {
    const newProduct: Product = {
      ...p,
      id: crypto.randomUUID(),
      status: 'Disponível',
      createdAt: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSale = (id: string) => {
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const updateSettings = (newSettings: any) => {
    setSettings(prev => ({ ...prev, ...newSettings }));
  };

  const importData = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.settings) setSettings(data.settings);
  };

  const sellProduct = (
    productId: string, 
    quantity: number,
    finalPrice: number, 
    cashAmount: number, 
    tradeItemValue: number, 
    date: string,
    tradeName?: string,
    tradeCategory?: string,
    tradeSuggestedPrice?: number
  ) => {
    const product = products.find(p => p.id === productId);
    if (!product || product.quantity < quantity) return;

    const newSale: Sale = {
      id: crypto.randomUUID(),
      productId: product.id,
      productName: product.name,
      quantity: quantity,
      date: date,
      finalPrice: finalPrice,
      cashAmount: cashAmount,
      tradeItemValue: tradeItemValue,
      tradeItemName: tradeName,
      purchasePrice: product.purchasePrice,
      profit: finalPrice - (product.purchasePrice * quantity)
    };

    setSales(prev => [newSale, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        const newQty = Math.max(0, p.quantity - quantity);
        return { 
          ...p, 
          quantity: newQty,
          status: newQty === 0 ? 'Vendido' : 'Disponível'
        };
      }
      return p;
    }));

    if (tradeItemValue > 0 && tradeName) {
      const tradedProduct: Product = {
        id: crypto.randomUUID(),
        name: tradeName,
        category: tradeCategory || 'Troca',
        purchasePrice: tradeItemValue,
        suggestedPrice: tradeSuggestedPrice || (tradeItemValue * 1.5),
        quantity: 1,
        status: 'Disponível',
        createdAt: new Date().toISOString()
      };
      setProducts(prev => [tradedProduct, ...prev]);
    }
  };

  return {
    products,
    sales,
    settings,
    currentView,
    setCurrentView,
    addProduct,
    updateProduct,
    deleteProduct,
    deleteSale,
    sellProduct,
    updateSettings,
    importData
  };
};

import React, { useState } from 'react';
import { Product } from '../types';
import { CATEGORIES, ICONS } from '../constants';
import { Search, ChevronRight, PackageOpen, AlertCircle, TrendingUp, Layers } from 'lucide-react';

interface SellProductModalProps {
  availableProducts: Product[];
  onClose: () => void;
  onConfirm: (productId: string, quantity: number, finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string, tradeSuggestedPrice?: number) => void;
}

const SellProductModal: React.FC<SellProductModalProps> = ({ availableProducts, onClose, onConfirm }) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchFilter, setSearchFilter] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const [sellQuantity, setSellQuantity] = useState<number>(1);
  const [cashAmount, setCashAmount] = useState<number>(0);
  const [tradeItemValue, setTradeItemValue] = useState<number>(0);
  const [tradeItemName, setTradeItemName] = useState<string>('');
  const [tradeItemCategory, setTradeItemCategory] = useState<string>(CATEGORIES[0]);
  const [tradeSuggestedPrice, setTradeSuggestedPrice] = useState<number>(0);
  const [saleDate, setSaleDate] = useState<string>(today);

  const filteredItems = availableProducts.filter(p => 
    p.name.toLowerCase().includes(searchFilter.toLowerCase()) || 
    p.category.toLowerCase().includes(searchFilter.toLowerCase())
  );

  const handleSelectProduct = (p: Product) => {
    setSelectedProduct(p);
    setSellQuantity(1);
    setCashAmount(p.suggestedPrice);
  };

  const finalPrice = (cashAmount || 0) + (tradeItemValue || 0);
  // O lucro é calculado sobre a quantidade vendida
  const totalCost = selectedProduct ? (selectedProduct.purchasePrice * sellQuantity) : 0;
  const realProfit = finalPrice - totalCost;

  const isPriceValid = selectedProduct ? finalPrice >= totalCost : true;
  const isQuantityValid = selectedProduct ? (sellQuantity > 0 && sellQuantity <= selectedProduct.quantity) : true;
  const tradeValidationFailed = (tradeItemValue > 0 && !tradeItemName) || (tradeItemName && tradeItemValue <= 0);

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-slate-900 w-full max-w-lg rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">

        {!selectedProduct ? (
          <div className="p-8 flex flex-col h-full overflow-hidden">
            <header className="mb-6">
              <h3 className="text-2xl font-bold text-white tracking-tight">Nova Venda / Brique</h3>
              <p className="text-slate-400 font-medium">Selecione o item que sairá do estoque.</p>
            </header>

            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                placeholder="Buscar item disponível..."
                value={searchFilter}
                onChange={e => setSearchFilter(e.target.value)}
                className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-4 text-white focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
              {filteredItems.length > 0 ? (
                filteredItems.map(p => (
                  <button 
                    key={p.id}
                    onClick={() => handleSelectProduct(p)}
                    className="w-full text-left p-4 bg-slate-800/40 hover:bg-slate-800 border border-slate-800 hover:border-blue-500/50 rounded-2xl flex items-center justify-between group transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-800 rounded-xl flex items-center justify-center font-bold text-slate-500 group-hover:text-blue-500 transition-colors">
                        {p.imageUrl ? <img src={p.imageUrl} className="w-full h-full object-cover rounded-xl" /> : <PackageOpen size={20}/>}
                      </div>
                      <div>
                        <p className="font-bold text-white group-hover:text-blue-400 transition-colors">{p.name}</p>
                        <p className="text-xs text-slate-500">{p.category} • {p.quantity} un. em estoque</p>
                      </div>
                    </div>
                    <ChevronRight size={18} className="text-slate-600 group-hover:text-blue-500 group-hover:translate-x-1 transition-all" />
                  </button>
                ))
              ) : (
                <div className="text-center py-10">
                  <p className="text-slate-500">Nenhum item disponível encontrado.</p>
                </div>
              )}
            </div>

            <button onClick={onClose} className="mt-6 w-full py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-2xl font-bold transition-all active:scale-95">Cancelar</button>
          </div>
        ) : (
          <div className="p-8 overflow-y-auto custom-scrollbar">
            <header className="mb-6 flex justify-between items-start">
              <div>
                <h3 className="text-2xl font-bold text-white tracking-tight">Detalhes do Brique</h3>
                <p className="text-slate-400 font-medium">Item: <span className="text-blue-400 font-bold">{selectedProduct.name}</span></p>
              </div>
              <button onClick={() => setSelectedProduct(null)} className="text-[10px] font-bold text-blue-500 uppercase tracking-widest bg-blue-500/10 px-3 py-1.5 rounded-full border border-blue-500/20 hover:bg-blue-500/20 transition-all">Trocar Item</button>
            </header>

            <div className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-800">
                  <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1">Data</label>
                  <input type="date" value={saleDate} onChange={e => setSaleDate(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 text-white font-medium" />
                </div>
                <div className={`bg-slate-800/50 p-4 rounded-2xl border ${!isQuantityValid ? 'border-red-500/50 ring-1 ring-red-500' : 'border-slate-800'}`}>
                  <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1">Qtd a Vender (Máx: {selectedProduct.quantity})</label>
                  <div className="flex items-center gap-2">
                    <Layers size={14} className="text-slate-500" />
                    <input 
                      type="number" 
                      min="1" 
                      max={selectedProduct.quantity}
                      value={sellQuantity} 
                      onChange={e => {
                        const val = parseInt(e.target.value) || 1;
                        setSellQuantity(val);
                        setCashAmount(selectedProduct.suggestedPrice * val);
                      }}
                      className="w-full bg-transparent border-none p-0 focus:ring-0 text-white font-bold" 
                    />
                  </div>
                </div>
              </div>

              <div className="bg-slate-800/30 p-5 rounded-3xl border border-slate-800/50">
                <div className="flex items-center gap-2 mb-2">
                  <div className="text-green-500">{ICONS.Money}</div>
                  <h4 className="text-xs font-bold text-slate-400 uppercase">Recebido em Dinheiro (Total)</h4>
                </div>
                <div className="flex items-center">
                  <span className="text-2xl font-bold text-slate-500 mr-2">R$</span>
                  <input type="number" value={cashAmount || ''} placeholder="0,00" onChange={e => setCashAmount(parseFloat(e.target.value) || 0)} className="flex-1 bg-transparent border-none text-2xl font-bold focus:ring-0 text-white p-0" />
                </div>
              </div>

              <div className={`p-5 rounded-3xl border transition-all ${tradeItemName || tradeItemValue > 0 ? 'bg-blue-600/10 border-blue-500/30' : 'bg-slate-800/30 border-slate-800/50 opacity-60'}`}>
                <div className="flex items-center gap-2 mb-4">
                  <div className="text-blue-400">{ICONS.Trade}</div>
                  <h4 className="text-sm font-bold text-slate-300 uppercase">Item de Troca (Opcional)</h4>
                </div>
                <div className="space-y-4">
                  <input type="text" placeholder="Nome do item recebido" value={tradeItemName} onChange={e => setTradeItemName(e.target.value)} className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-white text-sm" />
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 flex items-center">
                      <span className="text-sm font-bold text-slate-500 mr-1">R$</span>
                      <input type="number" placeholder="Custo" value={tradeItemValue || ''} onChange={e => setTradeItemValue(parseFloat(e.target.value) || 0)} className="flex-1 bg-transparent border-none text-sm font-bold text-white p-0" />
                    </div>
                    <div className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 flex items-center">
                      <span className="text-sm font-bold text-slate-500 mr-1">R$</span>
                      <input type="number" placeholder="P/ Venda" value={tradeSuggestedPrice || ''} onChange={e => setTradeSuggestedPrice(parseFloat(e.target.value) || 0)} className="flex-1 bg-transparent border-none text-sm font-bold text-white p-0" />
                    </div>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 rounded-2xl bg-slate-800 border border-slate-700 text-center">
                  <p className="text-[10px] uppercase font-bold text-slate-500 mb-1">Valor do Negócio</p>
                  <p className="text-xl font-black text-white">R$ {finalPrice.toFixed(2)}</p>
                </div>
                <div className={`p-4 rounded-2xl border text-center ${isPriceValid ? 'bg-green-500/10 border-green-500/20' : 'bg-red-500/10 border-red-500/20'}`}>
                  <p className={`text-[10px] uppercase font-bold mb-1 ${isPriceValid ? 'text-green-400' : 'text-red-400'}`}>{isPriceValid ? 'Lucro Bruto' : 'Prejuízo!'}</p>
                  <p className={`text-xl font-black ${isPriceValid ? 'text-green-400' : 'text-red-400'}`}>R$ {realProfit.toFixed(2)}</p>
                </div>
              </div>

              {!isQuantityValid && (
                <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-xl flex items-center gap-2">
                  <AlertCircle className="text-red-500" size={16} />
                  <p className="text-[10px] text-red-400 font-bold uppercase">Quantidade superior ao estoque disponível!</p>
                </div>
              )}

              <div className="flex gap-4 pt-2">
                <button onClick={onClose} className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl font-bold transition-all text-white">Cancelar</button>
                <button 
                  disabled={tradeValidationFailed || !isPriceValid || !isQuantityValid}
                  onClick={() => onConfirm(selectedProduct!.id, sellQuantity, finalPrice, cashAmount, tradeItemValue, saleDate, tradeItemName, tradeItemCategory, tradeSuggestedPrice)}
                  className="flex-1 py-4 bg-blue-600 hover:bg-blue-700 rounded-2xl font-bold transition-all disabled:opacity-50 text-white shadow-lg shadow-blue-900/20 active:scale-95"
                >
                  Confirmar Venda
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SellProductModal;

