                      <span className={`text-sm font-bold ${profitValue >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                        R$ {profitValue.toFixed(2)} ({profitPerc.toFixed(0)}%)
                      </span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-xs text-slate-500 font-semibold uppercase">Lucro Total Potencial</span>
                      <span className={`text-lg font-black ${totalProfitValue >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                        R$ {totalProfitValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
