                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir o produto "${confirmDelete?.name}"? Esta ação removerá o item permanentemente do seu estoque.`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default ProductList;

import React, { useState, useRef } from 'react';
import { Product, ProductStatus } from '../types';
import { ICONS, CATEGORIES } from '../constants';
import ConfirmModal from './ConfirmModal';
import { Camera, AlertCircle, TrendingUp, DollarSign, Layers, Loader2 } from 'lucide-react';

interface ProductListProps {
  products: Product[];
  onAdd: (p: any) => void;
  onUpdate: (p: Product) => void;
  onDelete: (id: string) => void;
}

const ProductList: React.FC<ProductListProps> = ({ products, onAdd, onUpdate, onDelete }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, name: string } | null>(null);
  const [filter, setFilter] = useState<string>('');
  const [categoryFilter, setCategoryFilter] = useState<string>('Todas');
  const [activeTab, setActiveTab] = useState<ProductStatus>('Disponível');
  const [isProcessingImage, setIsProcessingImage] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  const [newProduct, setNewProduct] = useState({
    name: '',
    category: CATEGORIES[0],
    purchasePrice: 0,
    suggestedPrice: 0,
    quantity: 1,
    imageUrl: ''
  });

  // Função otimizada para iOS para evitar estouro de memória (crash de tela preta)
  const processImageForIOS = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_SIZE = 500; // Resolução reduzida para máxima estabilidade no iOS
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_SIZE) {
              height *= MAX_SIZE / width;
              width = MAX_SIZE;
            }
          } else {
            if (height > MAX_SIZE) {
              width *= MAX_SIZE / height;
              height = MAX_SIZE;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) return reject('Canvas context failed');

          ctx.drawImage(img, 0, 0, width, height);

          // Exporta como JPEG com qualidade reduzida (0.6) para manter o arquivo minúsculo
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6);

          // Limpeza explicativa para o GC (Garbage Collector)
          canvas.width = 0;
          canvas.height = 0;

          resolve(dataUrl);
        };
        img.onerror = reject;
        img.src = e.target?.result as string;
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const calculateProfitValue = (purchase: number, suggested: number) => suggested - purchase;
  const calculateMargin = (purchase: number, suggested: number) => {
    if (purchase <= 0) return 0;
    return ((suggested - purchase) / purchase) * 100;
  };

  const isNewProductValid = newProduct.name.trim() !== '' && 
                            newProduct.purchasePrice > 0 && 
                            newProduct.suggestedPrice > 0 &&
                            newProduct.quantity > 0;

  const filteredProducts = products.filter(p => {
    if (!p) return false;
    const matchesName = (p.name || '').toLowerCase().includes(filter.toLowerCase());
    const matchesCat = categoryFilter === 'Todas' || p.category === categoryFilter;
    const matchesStatus = p.status === activeTab;
    return matchesName && matchesCat && matchesStatus;
  });

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean = false) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessingImage(true);
    try {
      const compressed = await processImageForIOS(file);
      if (isEdit && editingProduct) {
        setEditingProduct({ ...editingProduct, imageUrl: compressed });
      } else {
        setNewProduct(prev => ({ ...prev, imageUrl: compressed }));
      }
    } catch (err) {
      console.error("Erro ao processar imagem:", err);
      alert("Não foi possível carregar a imagem. Tente uma foto menor.");
    } finally {
      setIsProcessingImage(false);
      // Limpa o input para permitir selecionar a mesma imagem se necessário
      if (e.target) e.target.value = '';
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isNewProductValid) {
      onAdd(newProduct);
      setNewProduct({ name: '', category: CATEGORIES[0], purchasePrice: 0, suggestedPrice: 0, quantity: 1, imageUrl: '' });
      setShowAddModal(false);
    }
  };

  return (
