      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight">Produtos</h2>
          <p className="text-slate-400">Gerencie seu estoque e visualize seus lucros.</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-900/20 transition-all active:scale-95"
        >
          {ICONS.Plus} Novo Produto
        </button>
      </header>

      <div className="flex bg-slate-800/50 p-1.5 rounded-2xl border border-slate-700 max-w-fit">
        <button
          onClick={() => setActiveTab('Disponível')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'Disponível' 
            ? 'bg-blue-600 text-white shadow-lg' 
            : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          Disponíveis ({products.filter(p => p && p.status === 'Disponível').length})
        </button>
        <button
          onClick={() => setActiveTab('Vendido')}
          className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
            activeTab === 'Vendido' 
            ? 'bg-red-600 text-white shadow-lg' 
            : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          Vendidos ({products.filter(p => p && p.status === 'Vendido').length})
        </button>
      </div>

      <div className="flex flex-col sm:flex-row gap-3">
        <div className="flex-1 relative">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">{ICONS.Filter}</span>
          <input 
            type="text" 
            placeholder="Buscar por nome..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="w-full bg-slate-800 border-none rounded-2xl pl-12 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all text-white"
          />
        </div>
        <select 
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
          className="bg-slate-800 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-blue-500 appearance-none text-white min-w-[150px]"
        >
          <option>Todas</option>
          {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredProducts.map(p => {
          if (!p) return null;
          const profitValue = calculateProfitValue(p.purchasePrice, p.suggestedPrice);
          const totalProfitValue = profitValue * p.quantity;
          const profitPerc = calculateMargin(p.purchasePrice, p.suggestedPrice);
          const isSold = p.status === 'Vendido';

          return (
            <div key={p.id} className={`bg-card rounded-3xl border ${isSold ? 'border-slate-800 opacity-75' : 'border-slate-800'} overflow-hidden shadow-xl transition-all hover:border-slate-700 flex flex-col`}>
              <div className="relative h-48 bg-slate-800 flex items-center justify-center overflow-hidden">
                {p.imageUrl ? (
                  <img src={p.imageUrl} alt={p.name} className="w-full h-full object-cover" loading="lazy" />
                ) : (
                  <div className="text-slate-600 flex flex-col items-center gap-2">
                    {ICONS.Produtos}
                    <span className="text-[10px] uppercase font-bold tracking-widest">Sem Foto</span>
                  </div>
                )}
                <div className="absolute top-4 left-4 flex gap-2">
                  <span className={`text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-full border ${
                    isSold 
                    ? 'bg-red-500/20 text-red-400 border-red-500/30' 
                    : 'bg-green-500/20 text-green-400 border-green-500/30'
                  } backdrop-blur-md`}>
                    {p.status}
                  </span>
                  {!isSold && (
                    <span className="bg-blue-600/40 text-white text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-full border border-blue-500/30 backdrop-blur-md flex items-center gap-1">
                      <Layers size={10} /> {p.quantity} un.
                    </span>
                  )}
                </div>

                <div className="absolute top-4 right-4 flex gap-2">
                  <button 
                    onClick={() => setEditingProduct(p)}
                    className="p-2 bg-slate-900/60 text-white rounded-xl hover:bg-slate-900 transition-all backdrop-blur-md"
                  >
                    {ICONS.Edit}
                  </button>
                  <button 
                    onClick={() => setConfirmDelete({ id: p.id, name: p.name })}
                    className="p-2 bg-red-500/10 text-red-500 hover:bg-red-500 transition-all rounded-xl backdrop-blur-md"
                  >
                    {ICONS.Trash}
                  </button>
                </div>
              </div>

              <div className="p-6 flex-1">
                <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mb-1">{p.category}</p>
                <h3 className="text-xl font-bold mb-4 truncate text-white">{p.name || 'Sem nome'}</h3>

                <div className="space-y-3">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Unitário:</span>
                    <span className="font-bold text-slate-300">R$ {(p.purchasePrice || 0).toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-400">Venda:</span>
                    <span className="font-bold text-blue-400">R$ {(p.suggestedPrice || 0).toFixed(2)}</span>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            <div className="p-8 overflow-y-auto">
              <h3 className="text-2xl font-bold mb-6 text-white tracking-tight">Novo Produto</h3>
              <form onSubmit={handleSubmit} className="space-y-5">
                <div 
                  onClick={() => !isProcessingImage && fileInputRef.current?.click()}
                  className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden"
                >
                  {isProcessingImage ? (
                    <div className="flex flex-col items-center gap-2">
                       <Loader2 className="text-blue-500 animate-spin" size={32} />
                       <span className="text-xs font-bold text-slate-400 uppercase">Processando...</span>
                    </div>
                  ) : newProduct.imageUrl ? (
                    <img src={newProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors mb-2" size={32} />
                      <span className="text-xs font-bold text-slate-500 uppercase">Escolher Foto</span>
                    </>
                  )}
                  {/* Removido capture="environment" para abrir galeria por padrão no iOS */}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={(e) => handleImageUpload(e, false)} 
                    className="hidden" 
                    accept="image/*"
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input 
                    required
                    type="text" 
                    value={newProduct.name}
                    onChange={e => setNewProduct({...newProduct, name: e.target.value})}
                    placeholder="Ex: Tênis Air Max"
                    className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Categoria</label>
                    <select 
                      value={newProduct.category}
                      onChange={e => setNewProduct({...newProduct, category: e.target.value})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 appearance-none text-white"
                    >
                      {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Quantidade</label>
                    <input 
                      required
                      type="number" 
                      min="1"
                      value={newProduct.quantity}
                      onChange={e => setNewProduct({...newProduct, quantity: parseInt(e.target.value) || 0})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Preço Compra</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      value={newProduct.purchasePrice || ''}
                      onChange={e => setNewProduct({...newProduct, purchasePrice: parseFloat(e.target.value) || 0})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white font-bold"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Venda Sugerida</label>
                    <input 
                      required
                      type="number" 
                      step="0.01"
                      value={newProduct.suggestedPrice || ''}
                      onChange={e => setNewProduct({...newProduct, suggestedPrice: parseFloat(e.target.value) || 0})}
                      className="w-full bg-slate-800 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 text-white font-bold"
                    />
                  </div>
                </div>

                <div className="flex gap-4 mt-8">
                  <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white">Cancelar</button>
                  <button type="submit" disabled={!isNewProductValid || isProcessingImage} className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 py-4 rounded-2xl font-bold transition-all text-white shadow-lg shadow-blue-900/20">Salvar Item</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {editingProduct && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-md rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            <div className="p-8 overflow-y-auto">
              <h3 className="text-2xl font-bold mb-6 text-white tracking-tight">Editar Produto</h3>
              <form onSubmit={(e) => {
                e.preventDefault();
                onUpdate(editingProduct);
                setEditingProduct(null);
              }} className="space-y-5">
                <div onClick={() => !isProcessingImage && editFileInputRef.current?.click()} className="group relative h-40 bg-slate-800 rounded-3xl border-2 border-dashed border-slate-700 hover:border-blue-500 transition-all flex items-center justify-center cursor-pointer overflow-hidden">
                  {isProcessingImage ? (
                    <Loader2 className="text-blue-500 animate-spin" size={32} />
                  ) : editingProduct.imageUrl ? (
                    <img src={editingProduct.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <Camera className="text-slate-600 group-hover:text-blue-500 transition-colors" size={32} />
                  )}
                  <input type="file" ref={editFileInputRef} onChange={(e) => handleImageUpload(e, true)} className="hidden" accept="image/*" />
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase ml-2 mb-1 block">Nome do Item</label>
                  <input required type="text" value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-800 rounded-2xl p-4 border-none text-white" />
                </div>

                <div className="flex gap-4 mt-8">
                  <button type="button" onClick={() => setEditingProduct(null)} className="flex-1 bg-slate-800 hover:bg-slate-700 py-4 rounded-2xl font-bold transition-all text-white">Cancelar</button>
                  <button type="submit" disabled={isProcessingImage} className="flex-1 bg-blue-600 hover:bg-blue-700 py-4 rounded-2xl font-bold transition-all text-white shadow-lg shadow-blue-900/20">Salvar Alterações</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      <ConfirmModal 
        isOpen={!!confirmDelete}
        title="Excluir Produto"
        message={`Tem certeza que deseja excluir "${confirmDelete?.name}"?`}
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
};

export default ProductList;

import React, { useState, useRef, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProductList from './components/ProductList';
import SalesList from './components/SalesList';
import Reports from './components/Reports';
import SellProductModal from './components/SellProductModal';
import ConfirmModal from './components/ConfirmModal';
import { useAppState } from './hooks/useAppState';
import { Product } from './types';
import { ICONS } from './constants';
import { Download, Upload, Store, ShieldAlert, CheckCircle2, Infinity, Share } from 'lucide-react';

const App: React.FC = () => {
  const { 
    products, 
    sales, 
    settings,
    currentView, 
    setCurrentView, 
    addProduct,
    updateProduct,
    deleteProduct, 
    deleteSale,
    sellProduct,
    updateSettings,
    importData
  } = useAppState();

  const [isNewSaleModalOpen, setIsNewSaleModalOpen] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [showInstallPrompt, setShowInstallPrompt] = useState(false);
  const [editBusinessName, setEditBusinessName] = useState(settings.businessName);
  const fileImportRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Detecta se é iOS e se NÃO está rodando como PWA instalado
    const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
    const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (navigator as any).standalone;

    if (isIOS && !isStandalone) {
      setShowInstallPrompt(true);
    }
  }, []);

  const handleFinalizeSale = (productId: string, quantity: number, finalPrice: number, cash: number, tradeVal: number, date: string, tradeName?: string, tradeCategory?: string, tradeSuggestedPrice?: number) => {
    sellProduct(productId, quantity, finalPrice, cash, tradeVal, date, tradeName, tradeCategory, tradeSuggestedPrice);
    setIsNewSaleModalOpen(false);
    setCurrentView('Vendas');
  };

  const handleResetDatabase = () => {
    localStorage.clear();
    window.location.reload();
  };

  const handleExportData = () => {
    const data = {
      products,
      sales,
      settings,
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `brixlucro_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (confirm('Deseja realmente importar esses dados? Isso substituirá suas informações atuais.')) {
            importData(json);
            alert('Dados importados com sucesso!');
          }
        } catch (err) {
          alert('Erro ao importar arquivo. Verifique se o formato JSON é válido.');
        }
      };
      reader.readAsText(file);
    }
    if (fileImportRef.current) fileImportRef.current.value = '';
  };

  const renderView = () => {
    switch (currentView) {
      case 'Dashboard':
        return <Dashboard products={products} sales={sales} />;
      case 'Produtos':
        return (
          <ProductList 
            products={products} 
            onAdd={addProduct} 
            onUpdate={updateProduct}
            onDelete={deleteProduct} 
          />
        );
      case 'Vendas':
        return (
          <SalesList 
            sales={sales} 
            onDeleteSale={deleteSale} 
            onNewSale={() => setIsNewSaleModalOpen(true)} 
          />
        );
      case 'Relatórios':
        return <Reports sales={sales} products={products} />;
      case 'Configurações':
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
            <header>
              <h2 className="text-3xl font-bold text-white">Administração</h2>
              <p className="text-slate-400">Gerencie seu perfil, dados e segurança.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-blue-600/10 p-4 rounded-2xl text-blue-500">
                    <Store size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Perfil do Negócio</h3>
                </div>
                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-1 ml-1">Nome do Negócio</label>
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={editBusinessName}
                        onChange={(e) => setEditBusinessName(e.target.value)}
                        className="flex-1 bg-slate-800 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500 text-white"
                        placeholder="Ex: Minha Loja"
                      />
                      <button 
                        onClick={() => updateSettings({ businessName: editBusinessName })}
                        className="bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-xl transition-all active:scale-90"
                      >
                        <CheckCircle2 size={20} />
                      </button>
                    </div>
                  </div>
                  <div className="p-5 bg-amber-500/5 rounded-2xl border border-amber-500/20 flex items-center justify-between">
                    <div>
                      <p className="text-[10px] text-amber-500 uppercase font-black tracking-widest">Sua Licença BrixLucro</p>
                      <p className="font-black text-slate-100 text-lg flex items-center gap-2">
                        VITALÍCIA <Infinity size={18} className="text-amber-500" />
                      </p>
                    </div>
                    <div className="bg-amber-500/20 text-amber-500 text-[10px] font-black px-3 py-1.5 rounded-full border border-amber-500/30">ATIVO</div>
                  </div>
                </div>
              </div>

              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-green-600/10 p-4 rounded-2xl text-green-500">
                    <Download size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Gerenciamento de Dados</h3>
                </div>
                <p className="text-slate-400 text-sm mb-6">Mantenha seus dados seguros exportando um arquivo de backup.</p>
                <div className="grid grid-cols-1 gap-3">
                  <button 
                    onClick={handleExportData}
                    className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-2xl font-bold transition-all active:scale-95 border border-slate-700"
                  >
                    <Download size={18} /> Exportar Backup (JSON)
                  </button>
                  <button 
                    onClick={() => fileImportRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-bold transition-all active:scale-95"
                  >
                    <Upload size={18} /> Importar Dados (JSON)
                  </button>
                  <input 
                    type="file" 
                    ref={fileImportRef} 
                    onChange={handleImportFile} 
                    className="hidden" 
                    accept=".json"
                  />
                </div>
              </div>

              <div className="bg-card p-8 rounded-[2.5rem] border border-slate-800 shadow-xl md:col-span-2">
                <div className="flex items-center gap-4 mb-6">
                  <div className="bg-red-600/10 p-4 rounded-2xl text-red-500">
                    <ShieldAlert size={24} />
                  </div>
                  <h3 className="text-xl font-bold text-white">Zona de Perigo</h3>
                </div>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                  <div className="flex-1">
                    <p className="text-white font-bold mb-1">Limpar Base de Dados</p>
                    <p className="text-slate-400 text-sm">Apaga todos os dados localmente.</p>
                  </div>
                  <button 
                    onClick={() => setShowResetConfirm(true)}
                    className="px-8 py-4 bg-red-500/10 text-red-500 rounded-2xl font-bold hover:bg-red-600 hover:text-white transition-all shadow-lg active:scale-95 border border-red-500/20"
                  >
                    Resetar Sistema
                  </button>
                </div>
              </div>
            </div>

            <ConfirmModal 
              isOpen={showResetConfirm}
              title="Limpar Sistema?"
              message="Deseja realmente limpar todos os dados? Ação irreversível."
              confirmText="Limpar Tudo"
              onConfirm={handleResetDatabase}
              onCancel={() => setShowResetConfirm(false)}
            />
          </div>
        );
      default:
        return <Dashboard products={products} sales={sales} />;
    }
  };

  return (
    <Layout currentView={currentView} setCurrentView={setCurrentView}>
      {renderView()}

      {isNewSaleModalOpen && (
        <SellProductModal 
          availableProducts={products.filter(p => p.status === 'Disponível' && p.quantity > 0)} 
          onClose={() => setIsNewSaleModalOpen(false)}
          onConfirm={handleFinalizeSale}
        />
      )}

      {/* iOS PWA Install Instructions */}
      {showInstallPrompt && (
        <div className="fixed bottom-24 left-4 right-4 z-[100] animate-in slide-in-from-bottom-10">
          <div className="bg-blue-600 text-white p-6 rounded-[2rem] shadow-2xl border border-blue-400">
            <div className="flex items-start justify-between mb-2">
              <h4 className="font-bold text-lg">Instale para salvar dados!</h4>
              <button onClick={() => setShowInstallPrompt(false)} className="text-white/50">✕</button>
            </div>
            <p className="text-sm text-blue-100 mb-4 leading-snug">No iPhone, o Safari apaga dados se não estiver instalado. Instale o app na tela de início:</p>
            <div className="flex items-center gap-4 text-xs font-bold uppercase tracking-widest bg-blue-700/50 p-3 rounded-xl">
              <span className="flex items-center gap-1">Clique em <Share size={14} /></span>
              <span className="w-px h-3 bg-blue-500"></span>
              <span>"Tela de Início"</span>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;
